INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-05', E'꺾이지 않는 신앙 (다니엘 4장)', E'다니엘 4장', E'느부갓네살 왕이 전 세계에 보낸 조서는 참으로 놀라운 고백으로 시작됩니다. 한때 자신의 힘과 권세를 자랑하던 바빌론의 왕이 이제는 지극히 높으신 하나님의 이적과 놀라운 일을 선포하고 있습니다. 이 조서는 그가 겪은 일련의 사건들을 통해 하나님을 진정으로 알게 된 과정을 보여줍니다.\n\n왕궁에서 평안을 누리던 느부갓네살에게 하나님께서는 또 다른 꿈을 주십니다. 하늘까지 닿을 만큼 크고 견고한 나무가 베이고, 그 그루터기만 남아 일곱 때를 지내게 된다는 꿈이었습니다. 바빌론의 모든 지혜자들이 해석하지 못한 이 꿈의 의미를 다니엘은 정확하게 풀어냅니다. 그 거대한 나무는 바로 느부갓네살 자신이었고, 그가 교만으로 인해 하나님의 심판을 받게 될 것이라는 예언이었습니다.\n\n다니엘은 왕에게 공의를 행하고 가난한 자를 긍휼히 여김으로 평안을 구하라고 권면합니다. 그러나 열두 달이 지난 후, 왕궁 지붕을 거닐며 "이 큰 바벨론은 내가 능력과 권세로 건설하여 나의 도성으로 삼고 이것으로 내 위엄의 영광을 나타낸 것이 아니냐"(단 4:30)라고 자만하던 그 순간, 하나님의 심판이 즉시 임했습니다. 왕은 사람에게서 쫓겨나 일곱 때 동안 들짐승과 함께 지내며 소처럼 풀을 먹게 되었습니다.\n\n정해진 기한이 차고 느부갓네살이 하늘을 우러러보았을 때, 그의 총명이 회복되었습니다. 그는 비로소 지극히 높으신 하나님이 인간의 나라를 다스리시며, 자기 뜻대로 왕위를 주시고 빼앗으신다는 진리를 깨달았습니다. 회복된 왕은 하나님을 찬양하며 그분의 영원한 권세와 통치를 선포합니다. 하나님께서는 한 이방 왕의 교만을 꺾으시고, 그를 통해 온 세상에 자신이 진정한 주권자이심을 드러내셨습니다.', E'오늘의 핵심\n하나님께서는 교만한 느부갓네살을 낮추심으로써 모든 권세가 오직 하나님께로부터 온다는 진리를 깨닫게 하시고, 그를 통해 하나님의 주권을 만방에 선포하게 하셨습니다.\n\n묵상 질문\n1. 내가 스스로의 힘과 능력으로 이루었다고 자랑하는 것들은 무엇인가요?\n2. 하나님께서 내 교만을 꺾으시고 겸손을 가르치신 경험이 있나요?\n3. 오늘 내가 하나님의 주권을 인정하고 감사해야 할 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-06', E'우선순위를 기억하라 (학개 1장)', E'학개 1장', E'포로에서 돌아온 백성들이 성전 재건을 시작한 지 2년 만에 사마리아인들의 방해로 공사가 중단되었습니다. 그로부터 16년이라는 긴 세월이 흘렀습니다. 그 사이 백성들은 각자의 삶에 안주하며 자신의 집을 짓고 꾸미는 일에 열중했습니다. 바로 이때 하나님께서는 선지자 학개를 통해 날카로운 질문을 던지십니다. "이 성전이 황폐하였거늘 너희가 이 때에 판벽한 집에 거주하는 것이 옳으냐"(학 1:4).\n\n백성들은 아직 때가 이르지 않았다고 변명했지만, 하나님께서는 그들의 일상을 돌아보게 하십니다. 많이 뿌려도 수확이 적고, 먹어도 배부르지 못하며, 일해서 번 돈도 구멍 뚫린 주머니에 넣은 것처럼 사라져 버리는 현실. 이 모든 것이 하나님의 집을 황폐한 채로 두고 자신들의 안락함만 추구한 결과였습니다. 하나님께서는 가뭄과 흉작을 통해 그들의 우선순위가 잘못되었음을 깨닫게 하신 것입니다.\n\n놀라운 것은 학개의 메시지를 들은 백성들의 반응입니다. 총독 스룹바벨과 대제사장 여호수아를 비롯한 모든 백성이 하나님의 음성을 듣고 여호와를 경외하는 마음으로 돌아섰습니다. 그들이 순종의 마음을 품자 하나님께서는 즉시 "내가 너희와 함께 하노라"는 약속의 말씀을 주셨습니다. 더 나아가 하나님께서는 친히 그들의 마음을 감동시키셔서 성전 재건의 열정을 불타오르게 하셨습니다. 학개가 예언한 지 불과 23일 만에 백성들은 다시 성전 공사를 시작했습니다. 16년간 중단되었던 하나님의 일이 백성의 회개와 순종, 그리고 하나님의 감동하심을 통해 다시 시작된 것입니다.', E'오늘의 핵심\n하나님께서는 자신의 집보다 자기 집을 우선시하는 백성들을 책망하시고, 그들이 회개하고 돌이키자 함께하심의 약속과 성령의 감동으로 성전 재건의 열정을 회복시켜 주셨습니다.\n\n묵상 질문\n1. 나는 하나님의 일보다 내 일을 우선시하며 ''아직 때가 아니다''라고 변명하고 있지는 않나요?\n2. 내 삶에서 열심히 노력해도 열매가 없는 영역이 있다면, 혹시 하나님과의 관계가 우선순위에서 밀려난 것은 아닐까요?\n3. 하나님께서 "내가 너희와 함께 하노라"고 약속하실 때, 나는 어떤 순종의 결단으로 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-07', E'우선순위를 기억하라 (학개 2장)', E'학개 2장', E'성전 재건이 재개된 지 한 달이 지난 초막절 기간, 하나님의 말씀이 다시 학개를 통해 임합니다. 이제 막 기초공사를 시작한 성전을 바라보며 많은 사람들이 실망하고 있었습니다. 특히 포로로 잡혀가기 전 솔로몬 성전의 영광을 기억하는 노인들에게 초라한 기초는 눈물을 자아낼 만큼 보잘것없어 보였습니다. 그러나 하나님께서는 "스스로 굳세게 하여 일할지어다 내가 너희와 함께 하노라"(학 2:4)는 격려의 말씀으로 백성들을 위로하십니다.\n\n하나님께서는 출애굽 때 맺으신 언약을 상기시키시며, 그분의 영이 여전히 백성들 가운데 머물러 있음을 확증하십니다. 더 나아가 놀라운 약속을 주시는데, 이 성전의 나중 영광이 이전 영광보다 더 클 것이며, 모든 나라의 보배가 이 성전으로 모여들 것이라는 비전을 보여주십니다. 은과 금의 주인이신 하나님께서 친히 이 일을 이루실 것이기에, 현재의 초라함은 문제가 되지 않습니다.\n\n학개는 제사장들과의 문답을 통해 중요한 영적 원리를 가르칩니다. 거룩한 것이 닿는다고 해서 부정한 것이 거룩해지지 않지만, 부정한 것이 닿으면 거룩한 것도 부정해집니다. 이는 성전 건축을 중단했던 백성들의 모든 일이 하나님 앞에서 부정했음을 보여줍니다. 그러나 이제 성전 재건을 시작한 이날부터 하나님께서는 복을 약속하십니다.\n\n마지막으로 하나님께서는 총독 스룹바벨에게 특별한 약속을 주십니다. 열방이 진동하고 왕국들이 무너질 때, 하나님께서는 스룹바벨을 인장반지처럼 귀하게 여기실 것입니다. 이는 다윗 왕조의 회복과 메시아 왕국에 대한 소망을 담고 있으며, 궁극적으로 그리스도를 통해 성취될 하나님 나라의 약속입니다.', E'오늘의 핵심\n초라해 보이는 성전 재건 현장에서 낙심하는 백성들에게 하나님께서는 함께하심의 약속과 미래의 더 큰 영광을 보여주시며, 순종하는 자에게 복을 약속하십니다.\n\n묵상 질문\n1. 내가 하는 일이 보잘것없어 보일 때, 하나님의 임재와 약속을 붙잡고 있나요?\n2. 나의 삶에서 거룩함을 가로막는 ''부정한 것''은 무엇일까요?\n3. 하나님께서 나를 ''인장반지''처럼 귀히 여기신다는 사실이 오늘 나에게 어떤 위로와 힘을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-08', E'이스라엘의 구원 (스가랴 1장)', E'스가랴 1장', E'스가랴서는 포로 귀환 후 침체된 성전 재건 사업을 독려하며 시작됩니다. 학개와 함께 활동한 스가랴는 백성들에게 하나님의 마음을 전하는데, 그 첫 메시지는 "너희는 내게로 돌아오라"는 간절한 부르심이었습니다. 하나님께서는 조상들의 불순종으로 인한 70년 포로 생활의 아픔을 상기시키시며, 이제는 그 악한 길에서 돌이켜 하나님께로 돌아오기를 촉구하십니다.\n\n스가랴가 본 첫 번째 환상은 화석류나무 사이에 선 붉은 말 탄 자와 그 뒤의 말들이었습니다. 이들은 온 땅을 두루 다니며 살피는 하나님의 사자들로, 온 땅이 평안하고 조용하다고 보고합니다. 이 평안함은 역설적으로 이스라엘의 고통과 대조됩니다. 열방은 안일하게 지내는데 하나님의 백성은 여전히 고난 중에 있었던 것입니다.\n\n여호와의 천사가 "언제까지 예루살렘과 유다 성읍들을 불쌍히 여기지 아니하시려 하나이까"라고 중보할 때, 하나님께서는 선한 말씀과 위로의 말씀으로 응답하십니다. 하나님은 예루살렘을 위해 크게 질투하시며, 안일한 열방들에게는 진노하신다고 선포하십니다. 그들이 하나님의 심판 도구로 쓰임받았으나 도를 넘어 이스라엘을 괴롭혔기 때문입니다.\n\n네 뿔의 환상은 이스라엘을 흩어지게 한 열강들을 상징하며, 네 명의 대장장이는 그들을 심판할 하나님의 도구를 나타냅니다. 하나님께서는 당신의 백성을 괴롭힌 나라들을 반드시 심판하실 것입니다. 무엇보다 중요한 약속은 "내가 불쌍히 여기므로 예루살렘에 돌아왔은즉 내 집이 그 가운데에 건축되리니"라는 말씀입니다. 하나님께서 먼저 돌아오셨으니, 이제 백성들도 응답해야 할 때입니다.', E'오늘의 핵심\n하나님께서는 70년의 징계 후에도 당신의 백성을 포기하지 않으시고, 먼저 예루살렘으로 돌아오셔서 회복의 은혜를 베푸십니다.\n\n묵상 질문\n1. 하나님의 "내게로 돌아오라"는 부르심에 나는 어떻게 응답하고 있나요?\n2. 내 삶의 어려움 속에서도 나를 위해 중보하시는 주님의 음성을 듣고 있나요?\n3. 먼저 돌아오신 하나님의 사랑에 감사하며 오늘 내가 돌이켜야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-09', E'이스라엘의 구원 (스가랴 2장)', E'스가랴 2장', E'포로 생활에서 돌아온 백성들이 폐허가 된 예루살렘을 바라보며 막막해하던 때, 하나님께서는 스가랴에게 놀라운 환상을 보여주십니다. 측량줄을 든 한 사람이 예루살렘의 너비와 길이를 재려고 하자, 천사가 급히 달려가 전합니다. 예루살렘은 성곽 없는 성읍이 될 것이라는 선포였습니다. 고대 근동에서 성곽이 없다는 것은 무방비 상태를 의미했지만, 하나님께서는 친히 "불로 둘러싼 성곽"이 되시겠다고 약속하십니다.\n\n이 환상은 단순한 도시 재건 계획이 아닌, 하나님 나라의 무한한 확장을 보여주고 있습니다. 사람과 가축이 너무 많아 성곽으로 담을 수 없을 만큼 번성할 것이며, 하나님께서 친히 그들의 보호자가 되실 것입니다. 더 나아가 이방 나라들까지도 여호와께 속하여 하나님의 백성이 될 것이라는 원대한 비전이 선포됩니다.\n\n특별히 주목할 것은 "너희를 범하는 자는 그의 눈동자를 범하는 것이라"는 하나님의 선언입니다. 눈동자처럼 소중히 여기시는 백성을 향한 하나님의 극진한 사랑이 드러납니다. 비록 지금은 바벨론에 흩어져 있고 예루살렘은 폐허가 되었지만, 하나님께서는 여전히 그들을 버리지 않으셨습니다.\n\n"시온의 딸아 노래하고 기뻐하라"는 격려는 절망 가운데 있던 백성들에게 소망의 노래를 부르게 합니다. 하나님께서 친히 그들 가운데 거하시겠다는 약속은 성전 재건의 의미를 넘어서는 것이었습니다. 이는 훗날 그리스도를 통해 성취될 임마누엘의 약속을 가리키고 있습니다.', E'오늘의 핵심\n하나님께서는 폐허가 된 예루살렘에 대한 회복의 비전을 보여주시며, 친히 불 성곽이 되어 보호하시고 그 가운데 거하시겠다고 약속하십니다.\n\n묵상 질문\n1. 하나님께서 성곽 대신 친히 보호자가 되신다는 약속이 오늘 나에게 어떤 의미가 있을까요?\n2. 우리를 ''눈동자''처럼 여기시는 하나님의 사랑을 어떻게 경험하고 있나요?\n3. 절망적인 상황에서도 "노래하고 기뻐하라"고 하시는 하나님의 음성에 어떻게 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-10', E'이스라엘의 구원 (스가랴 3장)', E'스가랴 3장', E'스가랴가 본 네 번째 환상은 대제사장 여호수아의 정결케 됨에 관한 것입니다. 포로에서 돌아온 백성들을 이끌고 성전 재건에 나선 여호수아는 더러운 옷을 입은 채 여호와의 천사 앞에 서 있었고, 사탄은 그의 오른편에서 그를 고발하고 있었습니다. 그러나 하나님께서는 사탄을 책망하시며 여호수아를 "불에서 꺼낸 그슬린 나무"라고 부르십니다. 이는 바벨론 포로라는 심판의 불에서 건져낸 귀한 존재임을 보여주는 표현입니다.\n\n여호수아의 더러운 옷은 단순히 개인의 죄가 아니라 이스라엘 백성 전체의 죄악을 대표하는 것이었습니다. 대제사장은 백성을 대표하여 하나님께 나아가는 자였기에, 그의 부정함은 곧 백성 전체가 하나님 앞에 합당치 못함을 의미했습니다. 그러나 놀랍게도 하나님께서는 직접 여호수아의 더러운 옷을 벗기시고 아름다운 옷으로 갈아입히시며 정결한 관을 씌워주십니다. 이는 하나님의 일방적인 은혜로 이루어지는 죄사함과 회복을 보여줍니다.\n\n더 나아가 하나님께서는 여호수아와 그의 동료 제사장들을 "예표의 사람들"이라 부르시며, 장차 오실 "내 종 싹"에 대해 말씀하십니다. 이 싹은 메시아를 가리키는 것으로, 하루 만에 이 땅의 죄악을 제거하실 분입니다. 여호수아의 정결케 됨은 단지 당시의 회복만이 아니라, 장차 메시아를 통해 이루어질 완전한 구원을 미리 보여주는 그림자였습니다. 성전 재건의 과정에서 하나님께서는 단순히 건물의 회복이 아닌, 백성의 영적 회복과 미래의 완전한 구원을 약속하고 계셨던 것입니다.', E'오늘의 핵심\n하나님께서는 죄로 더러워진 백성을 친히 정결케 하시고, 메시아를 통한 완전한 구원을 약속하십니다.\n\n묵상 질문\n1. 사탄의 고발 앞에서도 하나님이 나를 "불에서 꺼낸 그슬린 나무"로 여기신다는 것이 어떤 위로가 되나요?\n2. 내 힘으로 벗을 수 없는 "더러운 옷"을 하나님께서 벗겨주시기를 기다리고 있나요?\n3. 여호수아처럼 정결케 된 후, 하나님께서 맡기신 사명을 신실하게 감당하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-12', E'이스라엘의 구원 (스가랴 4장)', E'스가랴 4장', E'포로에서 돌아온 백성들이 성전 재건을 중단한 채 16년이나 지났습니다. 주변 민족들의 방해와 경제적 어려움, 그리고 무엇보다 영적 무기력이 그들을 짓누르고 있었습니다. 이런 상황에서 하나님께서는 스가랴에게 다섯 번째 환상을 보여주십니다. 순금 등잔대와 그 양옆의 두 감람나무, 그리고 끊임없이 공급되는 기름의 환상은 좌절한 백성들에게 새로운 소망의 메시지를 전해줍니다.\n\n환상 속에서 천사는 스룹바벨에게 주시는 하나님의 말씀을 전합니다. "이는 힘으로 되지 아니하며 능력으로 되지 아니하고 오직 나의 영으로 되느니라"(슥 4:6). 성전 재건이라는 거대한 과업 앞에서 인간의 힘과 능력은 한계가 명확합니다. 페르시아 제국의 정치적 압력, 주변 민족들의 적대감, 경제적 궁핍 등 산처럼 큰 장애물들이 앞을 가로막고 있었습니다. 그러나 하나님께서는 이 모든 것이 성령의 능력으로 평지가 될 것임을 약속하십니다.\n\n특별히 주목할 것은 "작은 일의 날"에 대한 하나님의 격려입니다. 솔로몬 성전의 웅장함을 기억하는 노인들에게 스룹바벨이 재건하는 성전은 초라해 보였을 것입니다. 그러나 하나님께서는 작은 시작을 멸시하지 말라고 하십니다. 스룹바벨의 손에 든 다림줄은 비록 작은 도구이지만, 그것이 하나님의 영으로 인도받을 때 위대한 일을 이루게 됩니다.\n\n환상의 중심인 순금 등잔대는 하나님의 백성을, 두 감람나무는 기름부음 받은 지도자들을 상징합니다. 감람나무에서 끊임없이 공급되는 기름은 성령의 지속적인 임재와 능력을 보여줍니다. 이는 단순히 성전 건물의 재건만이 아니라, 하나님의 백성이 빛을 발하는 공동체로 회복되는 영적 재건을 의미합니다. 온 세상에 두루 다니시는 여호와의 눈이 지켜보시는 가운데, 시작한 자가 반드시 그 일을 완성하실 것입니다.', E'오늘의 핵심\n성전 재건의 완성은 인간의 힘이나 능력이 아닌 오직 하나님의 영으로 이루어지며, 작은 시작도 하나님의 손에서는 위대한 완성으로 이어집니다.\n\n묵상 질문\n1. 내 삶에서 인간적 힘과 능력의 한계를 느끼며 좌절하는 영역은 무엇인가요?\n2. 하나님께서 "작은 일의 날"이라고 부르시는 나의 작은 순종과 헌신은 무엇일까요?\n3. 성령의 기름 부으심이 끊이지 않도록 나는 어떻게 하나님과의 관계를 유지하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-13', E'성전 재건의 기쁨 (에스라 5장)', E'에스라 5장', E'오랜 침묵의 시간이 끝나고 하나님께서 다시 역사하십니다. 성전 재건이 중단된 지 16년, 백성들은 자신들의 집을 짓느라 바빴고 하나님의 집은 폐허로 남아 있었습니다. 그런데 다리오 왕 제2년, 선지자 학개와 스가랴가 하나님의 말씀을 선포하기 시작합니다. 이들의 예언은 단순한 책망이 아니라 하나님의 백성을 다시 일으켜 세우는 격려의 메시지였습니다.\n\n스룹바벨과 예수아는 선지자들의 말씀에 즉시 반응합니다. 그들이 성전 재건을 다시 시작하자, 유브라데 강 건너편 총독 닷드내와 그의 동료들이 찾아와 추궁합니다. "누가 너희에게 명령하여 이 성전을 건축하게 하였느냐?" 이전에도 이런 방해로 공사가 중단되었기에 백성들은 두려워할 수 있었습니다. \n\n그러나 이번에는 달랐습니다. 성경은 "하나님이 유다 장로들을 돌보셨으므로"(스 5:5)라고 기록합니다. 하나님의 특별한 보호하심이 그들과 함께했기에 총독들도 함부로 공사를 중단시킬 수 없었습니다. 오히려 그들은 다리오 왕에게 보고서를 올려 왕의 답변을 기다리게 됩니다.\n\n유다 장로들의 대답은 그들의 정체성과 사명을 분명히 보여줍니다. "우리는 천지의 하나님의 종이라"는 고백은 페르시아 제국의 권세 앞에서도 흔들리지 않는 신앙의 선언이었습니다. 그들은 조상들이 하나님을 노엽게 하여 성전이 파괴되고 포로가 되었던 역사를 정직하게 인정하면서도, 고레스 왕의 칙령에 따라 성전을 재건하고 있음을 당당히 밝힙니다.\n\n총독들이 올린 보고서는 공정하고 사실적이었습니다. 이들은 유다 백성의 주장을 그대로 전달하며 왕에게 고레스의 칙령을 확인해 볼 것을 제안합니다. 하나님께서는 방해하려던 자들의 보고서마저도 성전 재건을 돕는 도구로 사용하셨습니다. 16년 전의 좌절이 이제는 더 확실한 보장으로 바뀌어가고 있었습니다.', E'오늘의 핵심\n하나님께서는 선지자들의 격려와 특별한 보호하심으로 중단되었던 성전 재건 사역을 다시 시작하게 하시고, 방해하는 자들조차 하나님의 뜻을 이루는 도구로 사용하십니다.\n\n묵상 질문\n1. 내 삶에서 중단된 영적 사역이나 결심이 있다면 무엇 때문에 멈추었나요?\n2. 하나님의 돌보심을 경험했던 순간을 기억하며 감사를 고백해 보세요.\n3. "천지의 하나님의 종"이라는 정체성이 나의 일상에서 어떻게 나타나야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-14', E'성전 재건의 기쁨 (에스라 6장)', E'에스라 6장', E'다리오 왕이 보물전각에서 고레스 왕의 조서를 발견하는 순간, 하나님께서는 역사의 물줄기를 다시 돌려놓으셨습니다. 메대의 악메다 궁성에서 찾아낸 두루마리에는 예루살렘 성전 재건에 대한 구체적인 명령이 기록되어 있었습니다. 높이와 너비가 육십 규빗이며, 큰 돌 세 켜에 새 나무 한 켜를 놓고, 모든 경비는 왕실에서 부담한다는 내용이었습니다. 더욱이 느부갓네살이 탈취했던 성전 기물들을 돌려보내라는 명령까지 포함되어 있었습니다.\n\n다리오 왕의 새로운 조서는 단순히 성전 재건을 허락하는 것을 넘어섰습니다. 유브라데 강 건너편 총독들에게 공사를 방해하지 말 것을 명하고, 오히려 왕의 재산에서 경비를 끊임없이 지원하도록 했습니다. 제사에 필요한 수송아지와 양, 밀과 소금, 포도주와 기름까지 날마다 공급하라는 구체적인 지시가 내려졌습니다. 이전에는 방해꾼이었던 자들이 이제는 성전 건축을 돕는 조력자가 되었습니다.\n\n학개와 스가랴 선지자의 격려 가운데 유다 장로들이 공사를 진행하자 모든 일이 형통했습니다. 다리오 왕 제육년 아달월 삼일, 마침내 성전이 완공되었습니다. 이스라엘 백성은 수소 백 마리와 숫양 이백 마리, 어린 양 사백 마리를 드리며 기쁨으로 봉헌식을 거행했습니다. 제사장과 레위인들은 모세의 책에 기록된 대로 각자의 직무를 수행하기 시작했습니다.\n\n성전 완공 후 첫 유월절은 특별한 의미를 지녔습니다. "사로잡혔다가 돌아온 이스라엘 자손과 자기 땅에 사는 이방 사람의 더러운 것으로부터 스스로를 구별한 모든 이스라엘 사람들"(스 6:21)이 함께 유월절 양을 먹었습니다. 칠십 년의 포로 생활 후 처음으로 성전에서 드리는 유월절이었습니다. 이레 동안 무교절을 지키며 온 백성이 즐거워했습니다. 하나님께서 앗수르 왕의 마음까지 돌려 성전 건축을 돕게 하신 은혜를 깊이 체험한 것입니다.', E'오늘의 핵심\n하나님께서는 페르시아 제국의 행정 체계까지 사용하셔서 중단되었던 성전 재건을 완성하게 하시고, 회복된 예배를 통해 백성에게 참된 기쁨을 허락하셨습니다.\n\n묵상 질문\n1. 하나님께서 이방 왕의 마음을 돌이키셔서 당신의 뜻을 이루신 경험이 있으신가요?\n2. 오랜 기다림 끝에 이루어진 하나님의 약속을 경험하며 어떤 감사를 드렸나요?\n3. 회복된 예배가 내 삶에 가져다준 기쁨과 변화는 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-15', E'성벽 재건을 위한 열심 (느헤미야 4장)', E'느헤미야 4장', E'성벽 재건이 시작되자 적대 세력의 반응은 즉각적이었습니다. 산발랏은 유다 사람들을 공개적으로 조롱했고, 도비야는 "여우가 올라가도 곧 무너지리라"며 비웃었습니다. 이들의 조롱은 단순한 말의 공격을 넘어, 아라비아와 암몬, 아스돗 사람들과 연합하여 무력 공격을 모의하는 실질적인 위협으로 발전했습니다. 예루살렘을 치고 혼란을 일으키려는 그들의 계획은 막 시작된 재건 사업을 뿌리째 흔들려는 시도였습니다.\n\n더욱 어려운 것은 내부의 상황이었습니다. "짐을 나르는 자의 힘이 다 빠졌으니 우리가 성을 건축하지 못하리라"는 유다 사람들의 탄식은 육체적 피로를 넘어 심리적 좌절감을 드러내고 있습니다. 흙 무더기는 여전히 많은데 일꾼들의 기력은 소진되었고, 원수들의 근처에 사는 동족들은 열 번이나 찾아와 "너희가 우리에게로 와야 하리라"며 공사를 포기하도록 압박했습니다.\n\n이러한 안팎의 위기 앞에서 느헤미야가 보여준 리더십은 주목할 만합니다. 그는 먼저 하나님께 기도했지만, 동시에 구체적인 방어 전략을 세웠습니다. 성벽 뒤 낮고 넓은 곳에 종족별로 무장한 백성을 배치했고, 일꾼의 절반은 건축을, 절반은 경비를 서도록 했습니다. 특별히 "너희는 그들을 두려워하지 말고 지극히 크시고 두려우신 주를 기억하고 너희 형제와 자녀와 아내와 집을 위하여 싸우라"는 그의 외침은 백성들에게 싸워야 할 이유와 의지할 분을 분명히 제시했습니다.\n\n"우리 하나님이 우리를 위하여 싸우시리라"는 느헤미야의 선포는 단순한 정신적 위안이 아니었습니다. 하나님께서 실제로 대적들의 계략을 무너뜨리셨고, 백성들은 한 손에 연장을, 한 손에 병기를 들고 건축을 계속할 수 있었습니다. 밤에는 파수하고 낮에는 일하며, 물을 길으러 갈 때조차 병기를 놓지 않는 그들의 모습은 하나님을 의지하되 최선의 노력을 다하는 믿음의 본을 보여줍니다.', E'오늘의 핵심\n외부의 조롱과 위협, 내부의 피로와 좌절 속에서도 느헤미야는 기도와 실천을 병행하며 하나님께서 싸우시는 전쟁임을 선포했습니다.\n\n묵상 질문\n1. 일상의 도전과 위협 앞에서 나는 어떻게 반응하고 있나요?\n2. 기도하면서도 최선을 다해 준비하고 행동하는 균형을 유지하고 있나요?\n3. "우리 하나님이 우리를 위하여 싸우시리라"는 확신이 내 삶에 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-16', E'성벽 재건을 위한 열심 (느헤미야 5장)', E'느헤미야 5장', E'성벽 재건이 한창 진행되던 중, 예상치 못한 곳에서 위기가 터져 나왔습니다. 외부의 적이 아닌 내부의 갈등이었습니다. 백성들이 그들의 형제인 유다 사람들을 향해 부르짖기 시작했습니다. 어떤 이들은 가족을 먹일 양식이 없어 탄식했고, 어떤 이들은 흉년에 곡식을 얻으려 밭과 포도원을 저당 잡혔으며, 또 어떤 이들은 왕에게 세금을 바치려 빚을 내야 했습니다. 가장 가슴 아픈 것은 자녀들을 종으로 파는 지경에 이른 것이었습니다. 성벽은 세워지고 있었지만, 공동체는 무너지고 있었던 것입니다.\n\n느헤미야는 이 소식에 크게 노했습니다. 그러나 즉각적으로 대응하지 않고 깊이 생각한 후에 행동했습니다. 이것이 지도자의 지혜입니다. 그는 귀족들과 민장들을 모아 대회를 열고 그들의 잘못을 지적했습니다. "우리는 이방인의 손에 팔린 우리 형제 유다 사람들을 우리의 힘을 다하여 도로 찾았거늘 너희는 너희 형제를 팔고자 하느냐"(느 5:8). 느헤미야의 꾸짖음은 단순한 경제 문제를 넘어 하나님의 백성으로서의 정체성을 일깨우는 것이었습니다.\n\n더욱 놀라운 것은 느헤미야 자신의 모범이었습니다. 그는 12년간 총독의 녹을 받지 않았고, 오히려 매일 150명이 넘는 사람들을 자신의 상에서 대접했습니다. 이전 총독들이 백성을 압제하며 은 사십 세겔과 양식과 포도주를 빼앗았던 것과는 정반대의 모습이었습니다. 그는 "하나님을 경외하므로" 그렇게 행했다고 고백합니다.\n\n느헤미야의 리더십은 백성들의 마음을 움직였습니다. 귀족들은 즉시 이자 받기를 중단하고 빼앗은 것들을 돌려주겠다고 약속했으며, 실제로 그 말한 대로 행했습니다. 성벽 재건은 계속되었고, 더 중요하게는 무너졌던 공동체가 회복되었습니다. 오늘날 우리 사회와 교회 공동체에도 느헤미야와 같은 리더십이 필요합니다. 자신의 유익을 내려놓고 공동체를 섬기며, 하나님을 경외함으로 행동하는 지도자 말입니다.', E'오늘의 핵심\n느헤미야는 내부의 경제적 갈등을 하나님을 경외하는 마음과 솔선수범의 리더십으로 해결하며, 무너진 공동체를 회복시킵니다.\n\n묵상 질문\n1. 나는 어려움에 처한 이웃의 부르짖음에 어떻게 반응하고 있나요?\n2. 분노할 때 즉각 반응하지 않고 깊이 생각한 후 행동하고 있나요?\n3. 내가 가진 권리나 특권을 공동체를 위해 내려놓을 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-17', E'성벽 재건을 위한 열심 (느헤미야 6장)', E'느헤미야 6장', E'성벽 재건이 거의 완성 단계에 이르자 대적들의 방해는 더욱 교묘해졌습니다. 산발랏과 도비야는 이제 물리적 공격 대신 심리전을 택했습니다. 오노 평지에서 만나자는 제안은 화해의 제스처처럼 보였지만, 느헤미야는 그들의 진짜 의도를 꿰뚫어 보았습니다. "내가 이제 큰 역사를 하니 내려가지 못하겠노라"(느 6:3)는 그의 대답은 우선순위를 분명히 아는 사람의 지혜로운 거절이었습니다.\n\n네 번의 거절에도 포기하지 않은 산발랏은 다섯 번째에는 봉하지 않은 편지를 보냈습니다. 봉하지 않은 편지란 누구나 읽을 수 있도록 공개된 것으로, 느헤미야가 왕이 되려 한다는 거짓 소문을 퍼뜨리려는 의도였습니다. 페르시아 제국에서 반역 혐의는 곧 사형을 의미했기에, 이는 생명을 위협하는 모략이었습니다. 그러나 느헤미야는 동요하지 않았습니다. 오히려 "이제 내 손을 힘있게 하옵소서"라고 기도하며 하나님께 더욱 의지했습니다.\n\n더 충격적인 것은 내부의 배신이었습니다. 선지자로 자처하는 스마야가 성전 안으로 피신하라고 권했지만, 이는 율법을 어기게 하려는 함정이었습니다. 제사장이 아닌 사람이 성소에 들어가는 것은 율법 위반이었기 때문입니다. 느헤미야는 "나 같은 자가 어찌 도망하며"라고 당당히 거절했습니다. 하나님의 일을 하는 사람이 하나님의 법을 어기며 목숨을 구하는 것은 모순임을 알았던 것입니다.\n\n52일 만에 성벽이 완성되었을 때, 대적들은 크게 낙담했습니다. 그들이 두려워한 이유는 성벽의 견고함 때문이 아니라, "우리 하나님께서 이 역사를 이루신 것을" 깨달았기 때문입니다. 인간의 모든 방해와 음모를 뚫고 하나님의 뜻이 성취되는 것을 목격한 것입니다. 느헤미야가 보여준 분별력과 담대함은 하나님께 대한 확고한 신뢰에서 나왔고, 그 신뢰가 불가능해 보였던 일을 가능케 했습니다.', E'오늘의 핵심\n느헤미야는 대적들의 교묘한 음모와 내부의 배신 앞에서도 하나님께 대한 신뢰를 잃지 않았고, 분별력 있는 결단으로 마침내 52일 만에 성벽 재건을 완성했습니다.\n\n묵상 질문\n1. 좋은 제안처럼 보이는 유혹 앞에서 하나님의 일을 우선순위로 지키고 있나요?\n2. 두려움에 굴복하지 않고 "내 손을 힘있게 하옵소서"라고 기도할 때는 언제인가요?\n3. 하나님께서 이루신 일임을 주변 사람들이 인정할 만한 열매가 내 삶에 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-19', E'성벽 재건을 위한 열심 (느헤미야 7장)', E'느헤미야 7장', E'52일 만에 예루살렘 성벽이 완성되었습니다. 무너진 성벽을 다시 세우는 것은 단순히 돌을 쌓는 일이 아니었습니다. 그것은 하나님의 백성으로서의 정체성을 회복하고, 언약 공동체를 재건하는 거룩한 사역이었습니다. 느헤미야는 성벽 재건이라는 외적 과업을 마친 후, 이제 더 중요한 내적 재건에 착수합니다. 바로 백성들의 계보를 정리하고, 각자의 자리와 역할을 분명히 하는 일이었습니다.\n\n느헤미야가 가장 먼저 한 일은 신실한 지도자들을 세우는 것이었습니다. 그는 자신의 동생 하나니와 "충성스러운 사람이요 하나님을 경외함이 무리 중에서 뛰어난"(느 7:2) 하나냐를 예루살렘의 관원으로 임명합니다. 성벽은 완성되었지만 아직 경계를 늦출 수 없었기에, 문을 여닫는 시간과 파수의 방법까지 세심하게 지시합니다. 특별히 각 사람이 자기 집 맞은편을 지키게 한 것은, 공동체의 안전이 곧 자신의 안전임을 깨닫게 하는 지혜로운 배치였습니다.\n\n이어지는 긴 명단은 단순한 인구 조사가 아니었습니다. 바벨론 포로에서 귀환한 백성들의 계보를 확인하는 것은 언약 백성으로서의 정체성을 확인하는 작업이었습니다. 특히 제사장들 중 일부가 자신의 계보를 증명하지 못해 직무에서 배제된 것은, 하나님께 드리는 예배의 순결성을 지키려는 엄격한 조치였습니다. 이 명단 속에는 각 가문의 역사와 하나님의 신실하심이 담겨 있었습니다. 포로기를 거치면서도 자신들의 정체성을 잃지 않고 돌아온 4만 2360명의 백성들, 그들 하나하나가 하나님의 언약이 여전히 유효함을 증명하는 살아있는 증거였습니다.\n\n오늘날 우리도 때로는 자신의 영적 계보와 정체성을 점검해야 할 때가 있습니다. 내가 누구의 자녀이며, 어떤 믿음의 유산을 이어받았는지, 그리고 어떤 사명을 감당해야 하는지를 분명히 아는 것은 신앙생활의 기초입니다. 느헤미야가 보여준 것처럼, 외적인 성공 이후에도 내적인 정비를 게을리하지 않는 지혜가 필요합니다.', E'오늘의 핵심\n성벽 재건을 완성한 느헤미야는 신실한 지도자들을 세우고 귀환한 백성들의 계보를 정리하며, 언약 공동체의 정체성을 확립하는 내적 재건에 착수합니다.\n\n묵상 질문\n1. 하나님을 경외하는 리더를 세우는 일이 왜 중요할까요?\n2. 나의 영적 정체성과 계보를 분명히 알고 있나요?\n3. 외적 성취 후에도 내적 점검을 게을리하지 않으려면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-20', E'약속의 결정체, 예수', E'마태복음 1장', E'마태복음 1장은 아브라함부터 다윗, 다윗부터 바벨론 포로기, 바벨론 포로기부터 예수 그리스도에게로 이어지는 계보를 정리하고 있습니다. 마태는 1절에 아브라함과 다윗, 그리고 예수님, 이렇게 세 명의 이름으로 구약 2천 년을 담아 내고 있습니다. 또한 많은 왕들 중 유독 다윗에게만 ''왕''이라는 칭호를 붙여 다윗을 최대한 높여주었습니다. 그리고 이 족보에는 5명의 여인이 나오는데, 다른 사람들은 모두 이름으로 적은 것과 달리, 유독 밧세바를 ''우리야(우리아)의 아내''라고 적고 있습니다. 우리야의 아내 밧세바를 범한 잘못을 감추고 싶어서 충직한 신하였던 우리야를 전쟁으로 내몰아 죽인 다윗의 죄를 드러낸 것입니다. 이는 유대인들이 그토록 추앙하는 위대한 왕 다윗이라 할지라도 예수님의 십자가 보혈로 죄 사함을 받아야 할 한 사람의 죄인에 불과하다는 것을 강조하기 위해서였습니다. 모든 사람이 그분의 이름 앞에 꿇어 경배함이 마땅하다는 것이 마태가 하고 싶은 이야기입니다.\n예수님께서 유대 땅 베들레헴에 나실 때 동방박사들과 들녘의 목자들이 찾아와 아기 예수님의 탄생을 축하하며 기뻐했습니다. 예수님께서는 그 후 나사렛에서 자라신 후 세례 요한에게 세례를 받으시고 천국을 전파하시며 공생애를 시작하십니다.', E'오늘의 핵심\n하나님께서는 태초부터 계획하신 온 인류 구원의 약속을 실현하시고자 독생자 예수 그리스도를 이 땅에 보내십니다.\n\n묵상 질문\n하나님은 왜 불완전한 사람들의 계보 속에서 예수님을 약속하셨을까요?\n예수님의 족보에 죄인들이 포함된 것은 내 삶에 어떤 의미가 있을까요?\n하나님의 약속이 나를 통해 어떻게 이루어질 수 있도록 기도할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-21', E'예루살렘 입성과 예수의 설득 (마태복음 21장)', E'마태복음 21장', E'예루살렘으로 향하시는 예수님의 모습은 구약의 예언을 성취하는 동시에 우리의 기대를 뒤집습니다. 나귀 새끼를 타고 입성하시는 왕의 모습은 스가랴가 예언한 대로 "겸손하여 나귀, 곧 멍에 메는 짐승의 새끼를 탔도다"(21:5)라는 말씀을 그대로 이루어냅니다. 백성들은 겉옷을 길에 펴고 나뭇가지를 흔들며 "호산나 다윗의 자손이여!"라고 환호했지만, 그들이 기대한 정치적 메시아와 예수님이 보여주신 겸손한 왕의 모습 사이에는 큰 간극이 있었습니다.\n\n성전에 들어가신 예수님의 첫 행동은 매매하는 자들을 내쫓는 것이었습니다. 기도하는 집이어야 할 성전이 강도의 소굴로 변질된 현실은 당시 종교 지도자들의 영적 타락을 고스란히 드러내 줍니다. 그런 가운데서도 예수님은 맹인과 저는 자들을 고치시며 성전의 참된 목적, 곧 하나님의 치유와 회복이 일어나는 장소임을 몸소 보여주십니다.\n\n종교 지도자들과의 권위 논쟁은 그들의 위선을 더욱 선명하게 드러냅니다. 세례 요한의 권위를 인정하지 못하는 그들에게 예수님은 두 아들의 비유를 통해 말과 행동이 다른 신앙의 민낯을 보여주십니다. "가겠나이다"라고 대답했으나 가지 않은 맏아들은 바로 입술로는 하나님을 섬긴다 하면서 실제로는 순종하지 않는 그들의 모습이었습니다.\n\n포도원 농부의 비유는 더욱 날카롭게 그들의 죄악을 지적합니다. 하나님께서 맡기신 포도원을 자기 소유인 양 착각하고, 주인이 보낸 종들을 해치며, 급기야 아들까지 죽이는 농부들의 모습은 선지자들을 박해하고 이제 하나님의 아들까지 거부하는 이스라엘의 역사를 압축적으로 보여줍니다.\n\n무화과나무를 저주하신 사건도 같은 맥락에서 이해됩니다. 잎만 무성하고 열매가 없는 나무는 겉모습만 화려하고 실상은 열매 맺지 못하는 당시 종교의 현주소를 상징합니다. 예수님은 이를 통해 참된 믿음과 진실한 순종만이 하나님 앞에서 가치 있음을 가르쳐 주십니다.\n\n오늘 우리도 묻습니다. 나는 어떤 모습으로 주님을 맞이하고 있는가? 호산나를 외치는 입술만큼 삶에서도 겸손한 왕이신 예수님께 순종하고 있는가? 혹시 "가겠나이다"라고 대답만 하고 실제로는 움직이지 않는 신앙생활을 하고 있지는 않은가? 주님은 오늘도 우리에게 진실한 믿음과 행동이 일치하는 삶을 요구하십니다.', E'오늘의 핵심\n겸손한 왕으로 오신 예수님은 성전을 정결케 하시고, 두 아들과 포도원 농부의 비유를 통해 말과 행동이 일치하지 않는 종교 지도자들의 위선을 드러내십니다.\n\n묵상 질문\n1. 나는 호산나를 외치는 입술만큼 실제 삶에서도 예수님께 순종하고 있나요?\n2. 하나님께서 내게 맡기신 삶의 자리를 나의 소유인 양 움켜쥐고 있지는 않나요?\n3. 잎만 무성한 무화과나무가 아닌, 진실한 열매를 맺는 신앙생활을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-22', E'예루살렘 입성과 예수의 설득 (마태복음 22장)', E'마태복음 22장', E'예수님께서 들려주신 혼인 잔치 비유는 하나님 나라의 초청이 얼마나 은혜로운 것인지, 그리고 그 초청을 거절하는 것이 얼마나 어리석은 일인지를 보여줍니다. 임금이 아들의 혼인 잔치를 준비하고 사람들을 초청했으나, 청함을 받은 이들은 각자의 일상에 매여 그 귀한 초대를 외면합니다. 밭으로, 사업으로 가버린 그들의 모습은 하나님보다 세상일을 우선시하는 우리의 모습을 비춥니다. 더 나아가 종들을 해친 이들의 행위는 하나님의 메신저들을 거부하고 핍박했던 이스라엘의 역사를 압축적으로 보여줍니다.\n\n그러나 하나님의 초청은 멈추지 않습니다. 네거리로 나가 만나는 대로 사람들을 불러오는 장면은 복음이 유대인을 넘어 이방인에게까지 열렸음을 의미합니다. 다만 예복을 입지 않은 사람이 쫓겨나는 것은, 은혜로 주어진 구원이라 할지라도 그에 합당한 삶의 변화가 따라야 함을 가르쳐줍니다.\n\n이어지는 세 가지 논쟁은 예수님의 지혜와 권위를 더욱 선명하게 드러냅니다. 바리새인들과 헤롯당원들이 세금 문제로 함정을 파놓았을 때, "가이사의 것은 가이사에게, 하나님의 것은 하나님께"라는 예수님의 대답은 그들을 놀라게 했습니다. 이 말씀은 단순히 정교분리의 원칙을 넘어, 우리가 하나님의 형상대로 지음받은 존재로서 온전히 하나님께 속해야 함을 일깨워줍니다.\n\n사두개인들의 부활 논쟁에서도 예수님께서는 그들의 편협한 사고를 지적하십니다. "하나님은 죽은 자의 하나님이 아니요 살아 있는 자의 하나님"이라는 선언은 부활이 단지 미래의 사건이 아니라 지금도 살아계신 하나님과의 관계 속에서 경험되는 실재임을 보여줍니다.\n\n마침내 율법사가 가장 큰 계명을 묻자, 예수님께서는 하나님 사랑과 이웃 사랑으로 요약하십니다. 이 두 계명이 "온 율법과 선지자의 강령"이라는 말씀은, 수많은 규정과 전통에 매몰되어 있던 종교 지도자들에게 신앙의 본질을 일깨워주는 것이었습니다. 그리고 다윗이 메시아를 "주"라 부른 시편을 인용하시며, 예수님께서는 단순한 정치적 메시아가 아닌 하나님의 아들이심을 암시하십니다.', E'오늘의 핵심\n예수님께서는 혼인 잔치 비유와 세 가지 논쟁을 통해 하나님 나라의 초청에 합당하게 응답하는 삶과 참된 신앙의 본질이 무엇인지 가르쳐주십니다.\n\n묵상 질문\n1. 나는 하나님의 초청보다 일상의 바쁨을 핑계로 삼고 있지는 않나요?\n2. 하나님의 형상으로 지음받은 내가 온전히 하나님께 속한 삶을 살고 있나요?\n3. 하나님 사랑과 이웃 사랑의 계명을 실제 삶에서 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-23', E'예루살렘 입성과 예수의 설득 (마태복음 23장)', E'마태복음 23장', E'예수님께서 무리와 제자들에게 마지막으로 하신 공개 설교는 당시 종교 지도자들의 위선을 정면으로 다룹니다. "그들이 말하는 바는 행하고 지키되 그들이 하는 행위는 본받지 말라"는 말씀이 전체 메시지의 핵심을 담고 있습니다. 그들은 모세의 자리에 앉아 율법을 가르치면서도 정작 자신들은 그 율법의 정신을 따르지 않았던 것입니다.\n\n예수님은 일곱 번의 "화 있을진저"를 선포하시며 그들의 외식을 낱낱이 드러내십니다. 십일조는 철저히 드리면서 정의와 긍휼과 믿음은 버린 모습, 잔과 대접의 겉은 깨끗이 하면서 안은 탐욕으로 가득 채운 모습이 그들의 실상이었습니다. 특히 "회칠한 무덤"의 비유는 충격적입니다. 겉으로는 아름답게 보이지만 속은 죽음으로 가득한 무덤처럼, 그들의 신앙도 겉모습만 화려할 뿐이었습니다.\n\n그러나 이 엄중한 책망 가운데서도 예수님의 마음은 분명히 드러납니다. "암탉이 그 새끼를 날개 아래에 모음 같이 내가 네 자녀를 모으려 한 일이 몇 번이더냐"(마 23:37)라는 탄식에는 끝까지 그들을 구원하고자 하시는 간절함이 담겨 있습니다. 예수님의 책망은 정죄가 아닌 회개로의 초청이었던 것입니다.\n\n웨슬리가 강조했듯이, 참된 신앙은 내적 거룩함과 외적 행위가 일치하는 데 있습니다. 하나님께서는 우리의 겉모습이 아니라 중심을 보십니다. 오늘날 우리도 종교적 형식에만 매달리며 정작 하나님과의 관계는 소홀히 하고 있지는 않은지 돌아봐야 합니다. 신앙의 본질은 사람들에게 보이는 것이 아니라 하나님 앞에서의 진실함입니다. 예수님께서 가르치신 대로 "너희 중에 큰 자는 너희를 섬기는 자가 되어야" 합니다. 이것이 하나님 나라의 원리이며, 참된 제자도의 길입니다.', E'오늘의 핵심\n예수님은 종교 지도자들의 외식을 일곱 번의 "화 있을진저"로 책망하시면서도, 암탉이 새끼를 품듯 그들을 구원하고자 하시는 간절한 마음을 보여주십니다.\n\n묵상 질문\n1. 나의 신앙생활에서 겉모습과 속마음이 다른 부분은 없나요?\n2. 섬김의 리더십을 실천하기 위해 오늘 내가 할 수 있는 일은 무엇인가요?\n3. 예수님의 책망을 통해 회개하고 돌이켜야 할 영역이 있다면 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-24', E'예수의 이적과 가르침 (마가복음 4장)', E'마가복음 4장', E'예수님께서는 바닷가에서 큰 무리를 가르치셨습니다. 사람들이 너무 많아 배에 올라 앉으시고 해변에 모인 무리에게 비유로 말씀하셨는데, 그 중심에는 씨 뿌리는 자의 비유가 있었습니다. 같은 씨앗이 떨어진 땅의 상태에 따라 전혀 다른 결과를 맺는다는 이 비유는, 하나님의 말씀을 듣는 우리 마음의 상태가 얼마나 중요한지를 보여줍니다.\n\n길가와 같이 굳은 마음에는 말씀이 뿌리를 내리기도 전에 사탄이 빼앗아 갑니다. 돌밭 같은 마음은 처음에는 기쁨으로 받지만 시련이 오면 쉽게 포기합니다. 가시떨기 같은 마음은 세상의 염려와 재물의 유혹에 말씀이 막혀 열매를 맺지 못합니다. 그러나 좋은 땅과 같은 마음은 말씀을 듣고 받아 삼십 배, 육십 배, 백 배의 결실을 맺습니다. 예수님은 "들을 귀 있는 자는 들으라"(막 4:9)고 거듭 강조하시며, 듣는 것의 중요성을 일깨우십니다.\n\n이어지는 비유들도 하나님 나라의 신비를 드러냅니다. 등불은 감추려고 켜는 것이 아니라 비추려고 켜는 것처럼, 하나님의 진리는 결국 드러나게 됩니다. 씨앗이 땅에서 저절로 자라는 것처럼 하나님 나라는 우리가 이해할 수 없는 방식으로 성장하며, 작은 겨자씨가 큰 나무가 되듯 하나님 나라는 미약한 시작에서 놀라운 확장을 이룹니다.\n\n그날 저녁, 예수님은 하루 종일 가르치신 후 피곤하셨을 것입니다. 제자들과 함께 배를 타고 건너편으로 가시던 중, 고물에서 베개를 베고 깊이 잠드셨습니다. 그때 큰 광풍이 일어나 배에 물이 가득 차게 되자 제자들은 공포에 사로잡혔습니다. 예수님을 깨운 제자들에게 예수님은 먼저 바람과 바다를 꾸짖어 잠잠케 하신 후, 그들의 믿음 없음을 지적하셨습니다. 이 사건은 말씀의 권위를 가르치신 분이 곧 창조주 하나님의 권위를 가지신 분임을 보여줍니다. 제자들의 "그가 누구이기에"라는 질문은 오늘 우리에게도 동일하게 던져집니다.', E'오늘의 핵심\n예수님은 비유를 통해 하나님 나라의 비밀을 가르치시고, 자연을 다스리는 권능으로 자신이 누구인지를 계시하셨습니다.\n\n묵상 질문\n1. 내 마음은 어떤 밭과 같은가요? 말씀의 씨앗이 열매 맺지 못하게 하는 방해물은 무엇인가요?\n2. 인생의 풍랑 속에서도 평안히 주무실 수 있는 예수님을 신뢰하고 있나요?\n3. "그가 누구이기에"라는 제자들의 질문에 나는 어떤 고백으로 응답하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-26', E'예수의 이적과 가르침 (마가복음 5장)', E'마가복음 5장', E'바다 건너편 거라사인의 지방에 도착하신 예수님을 맞이한 것은 더러운 귀신 들린 한 사람이었습니다. 그는 무덤 사이에서 살며, 쇠사슬도 끊어버릴 만큼 강력한 힘에 사로잡혀 밤낮으로 소리 지르며 돌로 자기 몸을 해치고 있었습니다. 사람들이 포기한 이 한 영혼을 위해 예수님은 풍랑을 뚫고 오셨습니다. 귀신들이 돼지 떼로 들어가 이천 마리가 몰사하는 엄청난 경제적 손실이 발생했지만, 예수님께는 한 사람의 회복이 그 무엇보다 소중했습니다. 정신이 온전해진 그가 예수님과 함께 있기를 간청했을 때, 주님은 오히려 그를 가족에게 돌려보내며 하나님의 큰 일을 전하라고 하십니다. 구원받은 자의 첫 사명은 가장 가까운 곳에서 시작됨을 보여주십니다.\n\n다시 바다를 건너오신 예수님께 회당장 야이로가 찾아와 죽어가는 딸을 위해 간절히 구합니다. 그런데 가시는 길에 열두 해 동안 혈루증으로 고통받던 여인이 믿음으로 예수님의 옷자락을 만집니다. 율법상 부정한 자로 여겨져 사람들 틈에 끼일 수도 없었던 그녀는 "내가 그의 옷에만 손을 대어도 구원을 받으리라"는 믿음 하나로 무리 속을 헤치고 나아왔습니다. 예수님은 자기에게서 능력이 나간 것을 아시고 그녀를 찾으셨고, "딸아 네 믿음이 너를 구원하였으니"라며 공개적으로 그녀의 회복을 선포하십니다. \n\n이 지체로 인해 야이로의 딸이 죽었다는 소식이 전해집니다. 절망적인 순간, 예수님은 "두려워하지 말고 믿기만 하라"고 말씀하십니다. 죽음 앞에서도 믿음은 유효합니다. 예수님은 비웃는 무리를 물리치고 "달리다굼"이라는 아람어로 소녀를 일으키십니다. 열두 살 소녀와 열두 해 동안 병든 여인의 이야기가 교차하며, 예수님이 생명의 주관자이심을 선명하게 드러냅니다. 절망의 끝에서도, 모두가 포기한 곳에서도, 예수님은 한 영혼을 찾아오시고 회복시키시는 분이십니다.', E'오늘의 핵심\n예수님은 사회에서 버림받고 소외된 한 영혼을 위해 먼 길을 마다하지 않으시며, 절망적인 상황에서도 믿음으로 나아오는 자를 회복시키시는 생명의 주관자이십니다.\n\n묵상 질문\n1. 거라사 귀신 들린 자처럼 나도 무언가에 묶여 스스로를 해치고 있는 영역은 없나요?\n2. 혈루증 여인처럼 수치와 두려움을 넘어 믿음으로 예수님께 나아가야 할 일은 무엇인가요?\n3. "두려워하지 말고 믿기만 하라"는 예수님의 말씀이 오늘 내 상황에 어떻게 적용되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-27', E'예수의 이적과 가르침 (마가복음 6장)', E'마가복음 6장', E'마가복음 6장은 예수님의 사역이 점차 확장되면서 동시에 거부와 오해, 그리고 놀라운 기적이 교차하는 장면들을 보여줍니다. 고향 나사렛에서 시작되는 이 장은 예수님께서 어떻게 거절당하시면서도 끊임없이 사랑으로 다가가시는지를 생생하게 전해줍니다.\n\n예수님께서 고향 나사렛으로 돌아가셨을 때, 회당에서 가르치시는 그분의 지혜와 권능에 많은 사람들이 놀랐습니다. 그러나 놀라움은 곧 의심과 배척으로 바뀝니다. "이 사람이 마리아의 아들 목수가 아니냐"라는 그들의 반응은 너무나 익숙한 것에 가려져 하나님의 역사를 보지 못하는 인간의 한계를 드러냅니다. 예수님은 고향에서 아무 권능도 행하실 수 없으셨고, 그들의 불신앙을 이상히 여기셨다고 마가는 기록합니다.\n\n이어지는 세례 요한의 죽음은 의로운 자가 겪는 고난의 현실을 보여줍니다. 헤롯의 생일 잔치에서 벌어진 이 비극은 권력의 타락과 진리를 거부하는 인간의 어두운 면을 적나라하게 드러냅니다. 그러나 예수님은 이런 어둠 속에서도 멈추지 않으십니다.\n\n오천 명을 먹이신 기적은 예수님의 긍휼과 능력을 동시에 보여줍니다. 목자 없는 양 같은 무리를 보시고 불쌍히 여기신 예수님은 먼저 말씀으로 그들을 가르치셨고, 이어서 떡 다섯 개와 물고기 두 마리로 그들의 육신의 필요까지 채우셨습니다. 제자들이 "우리가 가서 이백 데나리온의 떡을 사다 먹이리이까"라고 계산적으로 접근할 때, 예수님은 그들에게 있는 작은 것으로 시작하라고 하십니다.\n\n밤 사경에 바다 위를 걸어오신 예수님의 모습은 자연을 다스리시는 창조주의 권능을 보여줍니다. 힘겹게 노를 젓는 제자들을 보시고 그들에게 오신 예수님. "안심하라 내니 두려워하지 말라"는 그분의 음성은 오늘도 인생의 풍랑 속에서 힘겹게 노를 젓는 우리에게 들려옵니다. 마가는 제자들이 떡 떼시던 일을 깨닫지 못하고 마음이 둔하여졌다고 지적하는데, 이는 우리도 일상에서 경험하는 하나님의 은혜를 얼마나 쉽게 잊어버리는지를 돌아보게 합니다.', E'오늘의 핵심\n예수님은 고향에서의 배척과 세례 요한의 죽음이라는 어둠 속에서도 긍휼의 마음으로 무리를 먹이시고, 풍랑 속의 제자들을 찾아오시는 참된 목자이십니다.\n\n묵상 질문\n1. 나는 혹시 너무 익숙한 것들 때문에 하나님의 놀라운 역사를 놓치고 있지는 않나요?\n2. 예수님께서 내 삶의 작은 것들을 사용하실 수 있도록 내어드릴 준비가 되어 있나요?\n3. 인생의 풍랑 속에서 "안심하라 내니"라고 말씀하시는 주님의 음성을 들으며 어떤 평안을 얻게 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-28', E'예수의 가르침과 이적 (누가복음 11장)', E'누가복음 11장', E'제자들이 예수님께 기도를 가르쳐 달라고 요청하자, 예수님께서는 하나님을 "아버지"라 부르며 시작하는 기도를 가르쳐 주십니다. 율법의 전통 속에서 하나님의 거룩하심만을 강조하던 유대인들에게, 하나님을 친밀한 아버지로 부르라는 가르침은 혁명적인 것이었습니다. 이어서 예수님께서는 밤중에 찾아온 친구의 비유를 통해 끈질긴 간구의 중요성을 보여주십니다. 하나님께서는 우리의 간절한 기도에 응답하시며, 악한 부모도 자녀에게 좋은 것을 줄 줄 아는데 하물며 하늘 아버지께서 구하는 자에게 성령을 주시지 않겠느냐고 말씀하십니다.\n\n예수님께서 벙어리 귀신을 쫓아내시자 일부 사람들은 바알세불의 힘을 빌렸다고 비난합니다. 그러나 예수님께서는 사탄의 나라가 스스로 분쟁하면 설 수 없다는 논리로 그들의 주장을 반박하시고, 하나님의 나라가 이미 임했음을 선포하십니다. 한 여인이 예수님의 어머니를 축복하자, 예수님께서는 "오히려 하나님의 말씀을 듣고 지키는 자가 복이 있느니라"(눅 11:28)고 말씀하시며 진정한 복의 의미를 가르치십니다.\n\n바리새인의 집에 초대받은 예수님께서는 손을 씻지 않고 식사하신 것을 문제 삼는 그들에게 날카로운 책망을 하십니다. 겉은 깨끗이 하면서 속은 탐욕과 악독으로 가득한 위선, 십일조는 철저히 드리면서 정의와 하나님 사랑은 소홀히 하는 형식주의, 명예와 인정받기를 좋아하는 교만함을 지적하십니다. 율법교사들에게도 지기 어려운 짐을 다른 사람에게 지우면서 자신들은 손가락 하나 대지 않는 위선을 꾸짖으십니다. 예수님의 이러한 책망은 종교적 외식과 형식주의에 빠진 당시 종교 지도자들의 실상을 적나라하게 드러내며, 참된 신앙이 무엇인지를 분명히 보여줍니다.', E'오늘의 핵심\n예수님께서는 하나님을 아버지로 부르는 친밀한 기도를 가르치시고, 종교적 형식주의와 위선을 날카롭게 책망하시며 마음의 진실함과 하나님 사랑의 실천을 강조하십니다.\n\n묵상 질문\n1. 내 기도가 형식적인 반복이 아니라 아버지와의 진실한 대화가 되고 있나요?\n2. 신앙의 겉모습은 그럴듯하지만 내면의 탐욕이나 교만은 없는지 돌아봅시다.\n3. 하나님의 말씀을 듣기만 하지 않고 삶으로 실천하기 위해 오늘 무엇을 할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-29', E'예수의 가르침과 이적 (누가복음 12장)', E'누가복음 12장', E'무리 수만 명이 모여들어 서로 밟힐 지경이 되었을 때, 예수님께서는 제자들에게 먼저 중요한 가르침을 주십니다. 바리새인들의 누룩, 곧 외식을 주의하라는 경고로 시작하신 말씀은 참된 신앙의 본질이 무엇인지 깨우쳐 줍니다. 겉으로 드러나는 경건의 모습이 아니라, 하나님 앞에서의 진실함이 중요함을 가르치시는 것입니다. 예수님은 숨겨진 것이 모두 드러날 것이며, 어둠 속에서 한 말이 빛 가운데 들릴 것임을 선포하십니다.\n\n이어서 예수님께서는 참으로 두려워해야 할 대상이 누구인지 분명히 밝히십니다. 몸은 죽여도 그 이상 아무것도 할 수 없는 사람이 아니라, 죽인 후에 지옥에 던질 권세를 가지신 하나님을 두려워해야 한다는 것입니다. 동시에 이 두려우신 하나님은 참새 한 마리도 잊지 않으시고, 우리의 머리카락까지 세신 바 되었을 만큼 세심하게 돌보시는 사랑의 하나님이심을 보여주십니다.\n\n무리 중 한 사람이 유산 분배 문제로 예수님께 도움을 청했을 때, 예수님은 어리석은 부자의 비유를 통해 참된 부요함이 무엇인지 가르치십니다. 곡식을 쌓을 곳간을 더 크게 짓고 안일함에 빠진 부자는 그날 밤 생명을 잃게 됩니다. 이 비유는 생명이 소유의 넉넉함에 있지 않으며, 하나님께 대하여 부요한 삶이 얼마나 중요한지를 일깨워줍니다.\n\n예수님께서는 제자들에게 염려하지 말라는 위로의 말씀을 주십니다. 까마귀도 먹이시고 백합화도 입히시는 하나님께서 하물며 그분의 자녀들을 돌보지 않으시겠냐는 것입니다. "너희는 무엇을 먹을까 무엇을 마실까 하여 구하지 말며 근심하지도 말라"(눅 12:29)고 하시며, 오직 하나님의 나라를 구하라고 명하십니다. 주인을 기다리는 종들의 비유를 통해서는 늘 깨어 준비하고 있어야 함을 가르치시며, 맡은 것에 충성하는 지혜로운 청지기의 자세를 강조하십니다.', E'오늘의 핵심\n예수님께서는 외식이 아닌 진실한 신앙, 세상의 부가 아닌 하나님께 대한 부요함, 염려 대신 하나님 나라를 구하는 삶의 우선순위를 가르치십니다.\n\n묵상 질문\n1. 나의 신앙생활 중에 남의 시선을 의식하는 외식적인 부분은 없나요?\n2. 물질적 안정을 추구하면서 정작 하나님께 대해 부요하지 못한 영역은 무엇인가요?\n3. 하나님 나라를 먼저 구하는 삶을 위해 오늘 내려놓아야 할 염려는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-30', E'예수의 가르침과 이적 (누가복음 13장)', E'누가복음 13장', E'빌라도가 갈릴리 사람들을 학살한 사건과 실로암 망대가 무너져 사람들이 죽은 참사가 예루살렘에서 화제가 되었습니다. 당시 유대인들은 이런 비극적 사건을 당한 사람들이 특별히 더 큰 죄인이었기 때문이라고 여기는 경향이 있었습니다. 그러나 예수님께서는 이러한 인과응보적 사고를 단호히 부정하시며, 오히려 모든 사람이 회개해야 할 필요성을 강조하십니다. 이어지는 열매 없는 무화과나무 비유는 하나님의 인내하시는 사랑과 동시에 회개의 시급성을 보여줍니다. 포도원 주인은 3년 동안 열매를 기다렸고, 포도원지기의 간청으로 한 해를 더 기다리기로 합니다. 이는 하나님께서 우리에게 주시는 은혜의 시간을 의미합니다.\n\n안식일에 18년 동안 귀신 들려 꼬부라진 여인을 고치신 사건은 예수님의 권위와 자비를 동시에 보여줍니다. 회당장은 안식일 규정을 들어 비난했지만, 예수님은 "아브라함의 딸"이라는 표현으로 이 여인의 존엄성을 회복시키시며, 안식일이야말로 사탄의 속박에서 해방되기에 가장 합당한 날임을 선포하십니다. 겨자씨와 누룩의 비유를 통해 하나님 나라가 작게 시작하지만 놀랍게 성장하고 변화시키는 능력이 있음을 가르치십니다.\n\n예루살렘으로 향하시는 여정 중에 누군가 구원받을 자가 적은지 물었을 때, 예수님은 좁은 문으로 들어가기를 힘쓰라고 답하십니다. 단순히 예수님과 함께 먹고 마셨다는 외적 관계가 아니라, 진정한 회개와 믿음의 응답이 필요함을 경고하십니다. 헤롯의 위협 앞에서도 예수님은 자신의 사명을 완수하기 위해 예루살렘으로 가야 함을 분명히 하시며, 선지자들을 죽인 예루살렘을 향한 애통한 탄식으로 이 장을 마무리하십니다. 암탉이 새끼를 품듯 사랑하시지만 거부당하신 하나님의 마음이 절절히 드러납니다.', E'오늘의 핵심\n예수님은 회개의 긴급성을 강조하시면서도, 동시에 하나님의 인내하시는 사랑과 구원의 문이 열려 있음을 보여주십니다. 그러나 그 문은 좁으며, 진정한 믿음의 응답이 요구됩니다.\n\n묵상 질문\n1. 남의 불행을 그들의 죄 때문이라고 쉽게 판단하는 내 모습은 없나요?\n2. 하나님께서 내게 주신 은혜의 시간 동안 나는 어떤 열매를 맺고 있나요?\n3. 예수님을 아는 것과 예수님께 알려지는 것의 차이는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-01', E'새 계명을 주심', E'요한복음 13장', E'유월절 엿새 전에 예수님께서는 나사로의 집으로 가셔서 거기서 유하십니다. 예수님을 위해 잔치할 때, 마리아가 비싼 향유를 예수님의 발에 부습니다. 가롯 유다가 그 여인의 행동을 책망하자 예수님께서는 "나의 장례할 날을 위하여 그것을 간직하게 하라"(요 12:7)라고 하시며 죽으심을 예고하십니다. 유대인의 큰 무리가 예수님께서 나사로의 집에 계시다는 소식을 듣고 그곳으로 옵니다. 나사로를 살리신 예수님과 정말로 나사로가 살아나는지를 보고 싶어 한 것입니다. 나사로에게 사람들이 많은 관심을 보이자 대제사장들은 나사로까지 죽이려고 모의합니다.\n이튿날, 예수님께서 예루살렘으로 오신다는 소식을 들은 큰 무리가 종려나무 가지를 가지고 "호산나 찬송하리로다 주의 이름으로 오시는 이 곧 이스라엘의 왕이시여"(요 12:13)라고 소리 높이며 예수님을 맞이합니다. 예수님께서는 마지막 만찬을 나누신 후 제자들의 발을 씻기시며 섬김의 본을 보여주십니다. 그리고 예수님께서는 제자들에게 "새 계명을 너희에게 주노니 서로 사랑하라 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라 너희가 서로 사랑하면 이로써 모든 사람이 너희가 내 제자인 줄 알리라"(요 13:34-35)라고 말씀하십니다.', E'오늘의 핵심\n제자들 그리고 이 땅에 있는 자신의 사람들을 사랑하시되 끝까지 사랑하신 예수님께서 "너희도 서로 사랑하라"라는 새 계명을 주십니다.\n\n묵상 질문\n1. 예수님의 죽음을 앞두고도 사랑으로 베푸신 그 마음은 무엇일까요?\n2. 자기 것을 아낌없이 드리는 마리아처럼 나는 무엇을 드릴 수 있을까요?\n3. 예수님의 죽음과 부활을 믿고 따르겠다고 기도할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-03', E'2차 전도여행 (사도행전 15장)', E'사도행전 15장', E'초대교회가 직면한 가장 중대한 신학적 도전이 예루살렘에서 논의되고 있었습니다. 유대로부터 내려온 어떤 사람들이 안디옥 교회에 와서 "모세의 법대로 할례를 받지 아니하면 능히 구원을 받지 못하리라"(행 15:1)고 가르치며 큰 파장을 일으켰습니다. 이는 단순한 의견 차이가 아니라 복음의 본질에 관한 문제였습니다. 은혜로 말미암는 구원인가, 아니면 율법의 행위가 더해져야 하는가? 이 논쟁으로 인해 바울과 바나바는 예루살렘으로 올라가게 됩니다.\n\n예루살렘 공의회에서 베드로는 고넬료 가정의 사건을 상기시키며 하나님께서 이방인들에게도 동일하게 성령을 주셨음을 증언합니다. 그는 "우리 조상과 우리도 능히 메지 못하던 멍에를 제자들의 목에 두려느냐"고 반문하며, 유대인이나 이방인이나 오직 주 예수의 은혜로 구원받는다는 복음의 핵심을 분명히 합니다. 야고보 역시 구약의 예언을 인용하며 이방인 선교가 하나님의 계획임을 확증합니다.\n\n공의회의 결정은 획기적이었습니다. 할례나 율법 준수를 구원의 조건으로 요구하지 않되, 우상 제물과 피와 목매어 죽인 것과 음행을 멀리하라는 최소한의 지침만을 제시합니다. 이는 율법주의를 거부하면서도 이방인 신자들이 유대인 신자들과 함께 교제할 수 있도록 배려한 지혜로운 결정이었습니다. 성령과 사도들이 함께 내린 이 결정은 안디옥 교회에 큰 위로와 기쁨을 가져다주었습니다.\n\n그러나 복음 전파를 위한 하나씩의 여정은 예상치 못한 갈등을 맞게 됩니다. 바울과 바나바가 마가 요한을 동행시키는 문제로 심히 다투어 결국 갈라서게 된 것입니다. 바나바는 마가와 함께 구브로로, 바울은 실라와 함께 수리아와 길리기아로 향합니다. 하나님께서는 이 아픈 분열마저도 복음이 더 넓은 지역으로 확산되는 계기로 사용하셨습니다.', E'오늘의 핵심\n예루살렘 공의회는 복음의 본질이 율법의 행위가 아닌 오직 예수 그리스도의 은혜임을 확증하며, 하나님께서는 인간의 갈등조차도 복음 확산의 도구로 사용하십니다.\n\n묵상 질문\n1. 나는 구원의 확신을 어디에 두고 있나요? 혹시 은혜 외에 다른 조건을 더하고 있지는 않나요?\n2. 신앙 공동체 안에서 의견 차이가 있을 때, 성령의 인도하심을 구하며 함께 분별하고 있나요?\n3. 동역자와의 갈등이 생길 때, 하나님께서 그 상황을 통해 이루실 더 큰 계획을 신뢰할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-04', E'2차 전도여행 (사도행전 16장)', E'사도행전 16장', E'바울의 2차 전도여행은 예상치 못한 만남과 인도하심으로 시작됩니다. 더베와 루스드라에서 바울은 디모데라는 젊은 제자를 만나게 되는데, 그는 믿는 유대인 어머니와 헬라인 아버지 사이에서 태어난 사람이었습니다. 바울이 그를 데리고 가면서 할례를 행한 것은 복음 전파에 걸림돌이 되지 않기 위한 목회적 배려였습니다. 이들이 여러 교회를 방문하며 예루살렘 공의회의 결정사항을 전달하자, 교회들은 믿음이 더욱 굳건해지고 날마다 성장하게 됩니다.\n\n그런데 바울의 계획과 달리 성령께서는 아시아에서 말씀을 전하지 못하게 막으셨고, 비두니아로 가려는 시도도 예수의 영이 허락하지 않으셨습니다. 드로아에서 바울이 본 마게도냐 사람의 환상은 하나님께서 유럽 선교의 문을 여시는 결정적인 전환점이 됩니다. 이렇게 복음은 아시아를 넘어 유럽 대륙으로 향하게 되었습니다.\n\n빌립보에서의 사역은 강가의 기도처에서 시작되었습니다. 자색 옷감 장사 루디아의 마음을 주께서 열어주셔서 바울의 말씀을 받아들이게 하셨고, 그녀와 온 집안이 세례를 받아 유럽 최초의 그리스도인이 됩니다. 그러나 점치는 귀신 들린 여종을 고친 일로 바울과 실라는 매를 맞고 깊은 옥에 갇히게 됩니다.\n\n한밤중 감옥에서 울려 퍼진 바울과 실라의 기도와 찬송은 놀라운 기적을 일으킵니다. 지진으로 옥문이 열렸으나 아무도 도망가지 않았고, 자결하려던 간수는 오히려 "내가 어떻게 하여야 구원을 받으리이까"라고 묻게 됩니다. 그 밤 간수와 온 가족이 세례를 받고 구원의 기쁨을 누리게 되었습니다. 고난 가운데서도 하나님께서는 복음의 능력을 나타내시고, 구원받을 영혼들을 예비하고 계셨던 것입니다.', E'오늘의 핵심\n성령의 인도하심을 따라 유럽으로 향한 바울은 빌립보에서 극심한 고난 속에서도 찬양하며, 간수의 가정에 구원의 역사를 일으킵니다.\n\n묵상 질문\n1. 내 계획과 달리 막히는 길이 있을 때, 그것이 더 큰 하나님의 계획을 위한 인도하심은 아닐까요?\n2. 고난의 한밤중에도 기도와 찬송을 드릴 수 있는 믿음이 내게 있나요?\n3. 루디아와 간수처럼 온 가족이 함께 믿음으로 나아가기 위해 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-05', E'2차 전도여행 (사도행전 17장)', E'사도행전 17장', E'바울의 두 번째 전도여행은 예상과는 다른 방향으로 전개되고 있었습니다. 데살로니가에서 바울은 자신의 관례대로 회당에 들어가 세 안식일 동안 성경을 가지고 강론합니다. 그의 메시지는 명확했습니다. 그리스도께서 고난을 받으시고 죽은 자 가운데서 부활하셔야 한다는 것, 그리고 이 예수님이 바로 그 그리스도라는 것이었습니다. 이 복음은 경건한 헬라인들과 귀부인들의 마음을 움직였지만, 유대인들의 시기심을 불러일으켰습니다. 그들은 폭도들을 동원해 도시를 소란케 하고, 바울 일행을 맞아들인 야손의 집을 습격했습니다. "천하를 어지럽게 하던 이 사람들"이라는 그들의 고발은 역설적으로 복음의 능력을 증명하는 것이었습니다.\n\n베뢰아 사람들의 반응은 데살로니가와는 대조적이었습니다. 그들은 더 너그러운 마음으로 말씀을 받았을 뿐 아니라, 날마다 성경을 상고하며 바울의 가르침이 진리인지 확인했습니다. 이러한 열린 자세와 성경 중심의 태도는 많은 이들을 믿음으로 인도했습니다. 그러나 데살로니가의 유대인들이 베뢰아까지 와서 소동을 일으키자, 바울은 아덴으로 떠나야 했습니다.\n\n철학의 도시 아덴에서 바울은 전혀 다른 청중을 만났습니다. 도시 곳곳에 가득한 우상들을 보며 마음에 격분한 바울은 회당뿐 아니라 장터에서도 복음을 전했습니다. 에피쿠로스와 스토아 철학자들은 그를 "말쟁이"라고 조롱했지만, 동시에 그의 새로운 가르침에 호기심을 보였습니다. 아레오바고에서의 설교는 바울의 지혜로운 복음 전도 방법을 보여줍니다. 그는 "알지 못하는 신"이라는 제단을 출발점으로 삼아, 창조주 하나님과 그분 안에서의 인간의 정체성, 그리고 부활하신 그리스도를 통한 심판의 메시지를 전했습니다. 청중의 반응은 엇갈렸지만, 아레오바고 관리 디오누시오와 다마리를 비롯한 몇 사람은 믿음을 갖게 되었습니다.', E'오늘의 핵심\n바울은 각 지역의 상황과 청중에 맞춰 복음을 전하되, 십자가와 부활의 핵심 메시지는 결코 타협하지 않았습니다.\n\n묵상 질문\n1. 베뢰아 사람들처럼 날마다 성경을 상고하며 진리를 확인하는 자세를 갖추고 있나요?\n2. 복음이 "천하를 어지럽게 한다"는 고발이 오늘날 우리에게는 어떤 의미일까요?\n3. 바울처럼 다양한 사람들에게 지혜롭게 복음을 전하려면 어떤 준비가 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-06', E'2차 전도여행 (사도행전 18장)', E'사도행전 18장', E'바울이 아덴을 떠나 고린도에 도착했을 때, 그곳에서 아굴라와 브리스길라 부부를 만나게 됩니다. 로마 황제 글라우디오의 유대인 추방령으로 인해 이탈리아에서 새로 온 이들과 바울은 같은 천막 제조업에 종사하며 함께 생활하게 되었습니다. 생업을 통해 자비량 선교를 감당하면서도 안식일마다 회당에서 복음을 전하는 바울의 모습은, 복음 전파자의 균형 잡힌 삶의 자세를 보여줍니다.\n\n실라와 디모데가 마게도냐로부터 도착하자, 바울은 더욱 말씀에 붙잡혀 예수가 그리스도이심을 힘있게 증언합니다. 그러나 유대인들의 강한 반대에 직면하자, 바울은 이방인 선교로 방향을 전환합니다. 회당장 그리스보와 많은 고린도 사람들이 복음을 받아들이고 세례를 받는 놀라운 일이 일어났습니다. 특히 주님께서 환상 중에 "두려워하지 말며 침묵하지 말고 말하라"(행 18:9)고 격려하시며, 이 성중에 주의 백성이 많음을 알려주신 것은 바울에게 큰 위로와 확신이 되었습니다.\n\n고린도에서 1년 6개월이라는 긴 시간 동안 말씀을 가르친 바울은, 갈리오 총독 앞에서 고발당하지만 오히려 보호받게 됩니다. 종교적 문제에 개입하지 않겠다는 갈리오의 판결은 복음 전파에 유리한 환경을 조성해 주었습니다. 이후 바울은 브리스길라와 아굴라와 함께 에베소로 향했고, 그곳에서 잠시 머문 후 예루살렘을 거쳐 안디옥으로 돌아갑니다.\n\n한편 알렉산드리아 출신의 아볼로가 에베소에서 열심히 가르치고 있었는데, 브리스길라와 아굴라가 그에게 하나님의 도를 더 정확하게 가르쳐 주었습니다. 이는 평신도 부부가 탁월한 설교자를 겸손히 인도하는 아름다운 동역의 모습을 보여줍니다. 아볼로는 이후 아가야로 건너가 은혜로 믿은 자들에게 큰 유익을 주며, 성경으로써 예수가 그리스도이심을 힘있게 증언했습니다.', E'오늘의 핵심\n고린도에서의 사역은 동역자들과의 만남, 주님의 직접적인 격려, 그리고 로마 정부의 보호라는 삼중의 은혜 가운데 풍성한 열매를 맺게 되었습니다.\n\n묵상 질문\n1. 바울이 천막 제조업을 하며 복음을 전한 것처럼, 나는 일상의 삶과 신앙을 어떻게 조화시키고 있나요?\n2. 주님께서 "두려워하지 말고 말하라"고 하신 말씀이 오늘 나에게는 어떤 의미로 다가오나요?\n3. 브리스길라와 아굴라처럼 다른 사람의 신앙 성장을 돕는 겸손한 동역자가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-07', E'성령이 주신 은사 (고린도전서 12장)', E'고린도전서 12장', E'고린도 교회는 놀라운 성령의 은사들을 경험하던 교회였습니다. 그러나 이 귀한 선물이 오히려 분열과 경쟁의 도구가 되어버린 안타까운 상황이 펼쳐지고 있었습니다. 바울은 이들에게 은사의 본질과 목적을 분명히 가르쳐 줍니다.\n\n먼저 바울은 모든 은사의 근원이 한 분 성령님이심을 강조합니다. "은사는 여러 가지나 성령은 같고"(고전 12:4)라는 선언을 통해, 다양한 은사들이 결코 우열을 가리는 기준이 될 수 없음을 분명히 합니다. 지혜의 말씀, 지식의 말씀, 믿음, 병 고치는 은사, 능력 행함, 예언, 영 분별, 방언, 통역 등 모든 은사는 같은 한 성령께서 그분의 뜻대로 각 사람에게 나누어 주시는 것입니다. 이 은사들은 개인의 영광을 위한 것이 아니라 "유익하게 하려 하심"이라고 바울은 그 목적을 분명히 밝힙니다.\n\n이어서 바울은 교회를 한 몸에 비유하면서 은사의 다양성이 가져야 할 조화로운 관계를 설명합니다. 손과 발, 눈과 귀가 각각 다른 기능을 가지고 있지만 모두가 한 몸을 이루듯이, 교회 안의 다양한 은사들도 그리스도의 한 몸을 섬기기 위한 것입니다. 특히 "더 약하게 보이는 몸의 지체가 도리어 요긴하고"라는 말씀은 화려해 보이는 은사에만 주목하던 고린도 교인들에게 큰 도전이 되었을 것입니다.\n\n바울의 가르침은 분명합니다. 하나님께서는 몸을 고르게 하시어 "몸 가운데서 분쟁이 없고 오직 여러 지체가 서로 같이 돌보게" 하셨다는 것입니다. 한 지체가 고통을 받으면 모든 지체가 함께 고통을 받고, 한 지체가 영광을 얻으면 모든 지체가 함께 즐거워하는 것이 그리스도의 몸 된 교회의 참모습입니다. 은사는 서로를 구별하고 높낮이를 가리는 도구가 아니라, 오히려 서로를 필요로 하고 돌보게 하는 하나님의 지혜로운 섭리였습니다.', E'오늘의 핵심\n성령의 은사는 다양하지만 그 근원은 한 분 성령님이시며, 이 은사들은 교회를 세우고 서로를 돌보기 위해 주어진 것입니다.\n\n묵상 질문\n1. 나는 다른 사람의 은사를 부러워하거나 내 은사를 자랑하고 있지는 않나요?\n2. 교회 안에서 약해 보이는 지체들을 더욱 귀하게 여기고 있나요?\n3. 내게 주신 은사를 교회 전체의 유익을 위해 어떻게 사용할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-08', E'성령이 주신 은사 (고린도전서 13장)', E'고린도전서 13장', E'사도 바울은 고린도전서 13장에서 모든 은사를 초월하는 가장 탁월한 길을 제시합니다. 그것은 바로 ''사랑''입니다. 고린도 교회는 영적 은사가 풍성했지만, 정작 가장 중요한 사랑을 잃어버린 공동체였습니다. 방언과 예언, 지식과 믿음의 은사를 자랑하며 서로 우열을 가리려 했던 그들에게 바울은 사랑 없는 은사의 무익함을 분명하게 가르쳐 줍니다.\n\n"내가 사람의 방언과 천사의 말을 할지라도 사랑이 없으면 소리 나는 구리와 울리는 꽹과리가 되고"(고전 13:1)라는 말씀은 사랑 없는 은사가 얼마나 공허한지를 보여줍니다. 아무리 뛰어난 영적 능력을 가졌다 해도, 심지어 모든 재산을 구제에 바치고 순교의 제물이 된다 해도, 사랑이 없으면 아무 유익이 없다는 것입니다. 이는 하나님께서 우리에게 은사를 주신 근본 목적이 사랑의 실천에 있음을 가르쳐 줍니다.\n\n바울이 묘사하는 사랑의 속성은 매우 구체적입니다. 사랑은 오래 참고, 온유하며, 시기하지 않고, 자랑하지 않으며, 교만하지 않습니다. 이러한 사랑의 특성들은 은사를 두고 경쟁하던 고린도 교인들의 모습과 정반대였습니다. 더 나아가 바울은 사랑의 영원성을 강조합니다. 예언도 폐하고 방언도 그치며 지식도 폐하겠지만, 사랑은 결코 떨어지지 않는다고 선포합니다. \n\n지금 우리가 아는 것은 부분적이고 희미하지만, 장차 하나님 앞에 설 때 온전히 알게 될 것입니다. 그때까지 우리에게 필요한 것은 믿음과 소망과 사랑입니다. 그중에서도 가장 위대한 것은 사랑입니다. 왜냐하면 사랑은 하나님의 본질이며, 모든 은사가 추구해야 할 궁극적 목표이기 때문입니다. 그리스도의 몸 된 교회는 이 사랑으로 하나 되고, 이 사랑으로 세상에 빛을 발하게 됩니다.', E'오늘의 핵심\n아무리 뛰어난 영적 은사를 가졌다 해도 사랑이 없으면 아무 의미가 없으며, 믿음과 소망과 사랑 중 가장 위대한 것은 영원히 남을 사랑입니다.\n\n묵상 질문\n1. 나는 은사나 능력을 추구하면서 정작 사랑을 놓치고 있지는 않나요?\n2. 바울이 말하는 사랑의 구체적인 속성 중 내게 가장 부족한 것은 무엇인가요?\n3. 영원히 남을 사랑을 실천하기 위해 오늘 내가 할 수 있는 작은 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-10', E'그리스도의 부활과 연보', E'고린도전서 16장', E'바울은 고린도 교인들을 향한 가르침의 마지막을 ''예수 그리스도의 부활''로 마무리하고 있습니다. 그리스도인은 부활을 소망하며 구별된 삶을 살아야 한다는 것입니다. 구별된 삶을 산다는 것은 세상에 휩쓸리지 않고 담대한 믿음으로 거룩한 삶을 살아야 함을 의미합니다. 바울은 로마 시민권을 소유한 사람이었지만, 천국의 시민권에 소망을 두고 있던 사람이었습니다. 이런 그가 고린도 교인들에게 썩어질 것을 붙들지 말고 썩지 않을 영원의 것을 붙잡으라고 조언합니다.\n바울은 편지 마지막 즈음에 예루살렘 교회 교인들을 돕기 위한 구제헌금에 적극 참여할 것을 독려합니다. 복음에 장애가 되지 않기 위해 자신의 필요를 스스로 채우던 바울이 가난하고 어려운 성도들의 필요를 채우는 일에는 교회가 적극적으로 나서도록 독려하고 있는 것입니다. 그리고 모든 사항에 대해 구체적인 대안을 알려준 바울은 마지막으로 "너희 모든 일을 사랑으로 행하라"(고전 16:14)라고 말합니다.\n바울은 이 편지를 써서 고린도 교회에 보낼 때, 아볼로에게 고린도로 다시 돌아가라고 여러 차례 권면했지만, 아볼로는 지금은 전혀 갈 마음이 없다고 합니다. 이제 디모데가 고린도 교회에 바울의 마음이 담긴 편지를 잘 소개할 것입니다.', E'오늘의 핵심\n바울은 부활을 소망하며 구별된 삶을 살자고 강조하고, 예루살렘 교회를 구제하는 일에 적극적으로 나서기를 독려합니다.\n\n묵상 질문\n1. 그리스도의 부활을 믿는 바울의 마음이 어떤 확신으로 가득했을까요?\n2. 내가 세상의 것보다 하나님 나라를 우선하고 있는지 돌아보고 계신가요?\n3. 부활의 소망 안에서 나는 어떻게 변화되길 원하시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-11', E'끊을 수 없는 하나님의 사랑', E'로마서 8장', E'로마서 8장은 "정죄함이 없다"는 선언으로 시작하여 "끊을 수 없는 사랑"이라는 확신으로 마무리됩니다. 이 한 장 안에 복음의 핵심이 온전히 담겨 있습니다.\n\n우리는 스스로의 힘으로 율법의 요구를 채울 수 없는 연약한 존재입니다. 그런데 하나님은 바로 그 연약함 속으로 아들을 보내셨습니다(3절). 우리가 자격을 갖춘 후에 사랑하신 것이 아니라, 죄 있는 육신의 모양으로 오셔서 우리 대신 죄를 정하셨습니다. 이 은혜 위에서 성령은 우리를 ''종''이 아닌 ''자녀''로 부르시며, "아빠 아버지"라 부를 수 있는 친밀한 관계 안으로 이끌어 주십니다(15절).\n\n물론 자녀가 되었다고 해서 고난이 사라지는 것은 아닙니다. 바울은 환난, 곤고, 박해, 기근, 위험까지 구체적으로 나열합니다(35절). 직장에서의 부당한 대우, 관계의 상처, 보이지 않는 미래 앞에서 느끼는 불안 — 이 모든 것이 우리를 흔들 수 있습니다. 그러나 바울은 단호하게 선언합니다. 이 모든 일에 "우리를 사랑하시는 이로 말미암아 넉넉히 이기느니라"(37절). 우리의 승리는 고난이 없어져서가 아니라, 고난 한가운데서도 끊어지지 않는 하나님의 사랑에 근거합니다.\n\n더 놀라운 것은 우리가 기도조차 제대로 못 할 때, 성령이 말할 수 없는 탄식으로 친히 간구하신다는 사실입니다(26절). 하나님의 사랑은 우리의 신앙 상태에 따라 오르내리지 않습니다. 사망도, 생명도, 현재 일도, 장래 일도, 그 어떤 피조물도 그리스도 예수 안에 있는 이 사랑을 끊을 수 없습니다(38-39절).\n\n지금 나를 흔드는 것은 무엇입니까? 그것이 아무리 크게 느껴지더라도, 그것은 ''피조물''에 불과합니다. 오늘 이 사랑 안에 내가 서 있음을 기억하며, 두려움 대신 "아빠 아버지"를 부르는 하루가 되시길 바랍니다.', E'오늘의 핵심\n세상의 무엇도 하나님의 사랑에서 우리를 끊을 수 없으며, 현재의 고난은 장차 나타날 영광과 비교할 수 없습니다.\n\n묵상 질문\n1. 하나님의 사랑에서 우리를 끊을 수 있는 것은 아무것도 없다는 사실을 마음 깊이 믿고 계신가요?\n2. 지금 느끼는 두려움이나 외로움이 있다면, 그것을 하나님의 사랑 앞에 내려놓을 수 있으신가요?\n3. 오늘 하루 하나님의 끊을 수 없는 사랑을 의지하며 살겠다고 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-12', E'그리스도인의 새로운 삶 (로마서 12장)', E'로마서 12장', E'바울은 로마서 1장부터 11장까지 하나님의 구원의 은혜를 깊이 있게 풀어낸 뒤, 12장에 이르러 "그러므로"라는 한 단어로 방향을 전환합니다. 그 놀라운 은혜를 받은 사람이라면, 이제 어떻게 살아야 하는가를 이야기하는 것입니다. 바울의 첫 번째 권면은 우리의 몸을 하나님이 기뻐하시는 거룩한 산 제물로 드리라는 것입니다. 구약의 제사가 죽은 짐승을 바쳤다면, 이제는 살아 있는 우리의 삶 전체가 제물이 됩니다. 출근길도, 시험 준비도, 사람을 만나는 시간도 모두 예배가 될 수 있다는 뜻입니다.\n\n이러한 헌신은 마음의 변화로부터 시작됩니다. 바울은 "이 세대를 본받지 말고 오직 마음을 새롭게 함으로 변화를 받아"(롬 12:2)라고 권면합니다. 세상의 가치관에 휩쓸리지 않고 하나님의 뜻을 분별하려면, 먼저 우리의 생각과 마음이 새로워져야 합니다. 이것은 단순한 결심이 아니라 성령께서 우리 안에서 이루시는 지속적인 변화의 과정입니다.\n\n이어서 바울은 공동체 안에서의 삶을 이야기합니다. 우리는 그리스도 안에서 한 몸의 지체이며, 각자에게 주어진 은사가 다릅니다. 섬기는 사람은 섬기는 일로, 가르치는 사람은 가르치는 일로, 위로하는 사람은 위로하는 일로 충실하면 됩니다. 누군가의 은사를 부러워하거나 자신의 자리를 하찮게 여길 필요가 없습니다. 각자의 자리에서 받은 은사대로 섬길 때 그리스도의 몸이 온전하게 세워집니다.\n\n바울이 특별히 강조하는 것은 진실한 사랑입니다. "사랑에는 거짓이 없나니"라는 선언으로 시작해서, 즐거워하는 자와 함께 즐거워하고 우는 자와 함께 울라고 권합니다. 심지어 원수를 축복하고, 원수가 주리면 먹이고 목마르면 마시게 하라고 합니다. 이것은 인간의 본성으로는 불가능한 일입니다. 오직 하나님의 은혜를 깊이 경험한 사람만이 이런 사랑을 실천할 수 있습니다. 악을 악으로 갚는 세상의 방식이 아니라, 선으로 악을 이기는 하나님의 방식으로 살아가는 것, 이것이 바로 산 제물로 드려진 삶의 모습입니다.', E'오늘의 핵심\n하나님의 은혜를 받은 그리스도인은 자신의 삶 전체를 산 제물로 드리며, 진실한 사랑으로 공동체를 섬기고 선으로 악을 이기는 삶을 살아갑니다.\n\n묵상 질문\n1. 내 일상의 어떤 부분을 거룩한 산 제물로 드릴 수 있을까요?\n2. 하나님께서 내게 주신 은사는 무엇이며, 그것으로 공동체를 어떻게 섬길 수 있을까요?\n3. 최근에 악을 선으로 갚아야 할 상황이 있었나요? 어떻게 반응했나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-13', E'그리스도인의 새로운 삶 (로마서 13장)', E'로마서 13장', E'바울이 로마서 13장에서 펼치는 가르침은 당시로서는 매우 파격적이었습니다. 로마 제국의 압제 아래 고통받던 그리스도인들에게 "위에 있는 권세들에게 복종하라"고 권면하는 것은 쉽지 않은 일이었을 것입니다. 그러나 바울은 모든 권세가 하나님으로부터 나왔음을 분명히 하면서, 세상 권력도 하나님의 주권 아래 있음을 가르칩니다. 이는 무조건적인 복종을 의미하는 것이 아니라, 하나님께서 세우신 질서를 인정하고 그 안에서 선을 행하라는 뜻입니다.\n\n바울은 권세자들을 ''하나님의 사역자''라고 부르며, 그들이 선을 행하는 자에게는 칭찬을, 악을 행하는 자에게는 심판을 베푸는 역할을 한다고 설명합니다. 따라서 그리스도인들은 두려움 때문이 아니라 양심을 따라 복종해야 하며, 조세를 바치는 것도 같은 맥락에서 이해해야 합니다. 이는 초대교회가 로마 사회 안에서 책임감 있는 시민으로 살아가며 복음을 전파하는 지혜로운 전략이기도 했습니다.\n\n그런데 바울은 갑자기 화제를 전환하여 사랑의 빚을 이야기합니다. "피차 사랑의 빚 외에는 아무에게든지 아무 빚도 지지 말라"는 권면은 앞의 시민적 의무와 대조를 이룹니다. 조세는 다 내면 끝나지만, 사랑의 빚은 평생 갚아도 끝이 없다는 의미입니다. 바울은 모든 계명이 "네 이웃을 네 자신과 같이 사랑하라"는 말씀 안에 포함된다고 선언합니다. 사랑이야말로 율법의 완성이며, 이웃에게 악을 행하지 않는 것이 사랑의 가장 기본적인 표현입니다.\n\n장의 마지막에서 바울은 종말론적 긴급성을 강조합니다. "밤이 깊고 낮이 가까웠으니"라는 표현은 그리스도의 재림이 임박했음을 암시합니다. 그러므로 그리스도인들은 어둠의 일을 벗어버리고 빛의 갑옷을 입어야 합니다. 방탕, 술 취함, 음란, 다툼, 시기와 같은 어둠의 일들을 버리고, "주 예수 그리스도로 옷 입고" 살아가라는 권면은 매우 구체적입니다. 이것은 단순한 도덕적 교훈이 아니라, 다시 오실 주님을 기다리는 삶의 자세를 보여줍니다. 오늘 우리가 국가와 사회에 책임을 다하고, 이웃을 진심으로 사랑하며, 거룩한 삶을 추구하는 것은 모두 그리스도의 재림을 준비하는 일입니다.', E'오늘의 핵심\n그리스도인은 하나님이 세우신 권세에 순종하며 시민의 의무를 다하되, 무엇보다 사랑으로 율법을 완성하고 그리스도의 재림을 준비하는 거룩한 삶을 살아야 합니다.\n\n묵상 질문\n1. 하나님께서 세상의 권세를 통해서도 일하신다는 사실이 나의 시민생활에 어떤 의미를 주나요?\n2. 사랑의 빚을 평생 갚아가야 한다면, 오늘 내가 갚을 수 있는 구체적인 방법은 무엇일까요?\n3. 그리스도의 재림을 기다리며 ''빛의 갑옷''을 입는다는 것은 일상에서 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-14', E'땅 끝 비전과 받음직한 섬김 (로마서 15장)', E'로마서 15장', E'바울은 로마 교회 안의 갈등을 다루면서 믿음이 강한 자들에게 특별한 책임을 부여합니다. 그들은 마땅히 믿음이 약한 자의 약점을 담당하고 자기를 기쁘게 하지 말아야 한다고 권면합니다. 이는 그리스도께서 보여주신 모범을 따르는 것입니다. 그리스도는 자기를 기쁘게 하지 않으셨고, 오히려 우리를 위해 모든 비방을 담당하셨습니다. 바울은 이러한 그리스도의 사랑을 본받아 서로를 받으라고 권합니다.\n\n바울은 자신의 사도직 소명에 대해 분명히 밝힙니다. 하나님께서 그에게 주신 은혜는 이방인을 위한 그리스도 예수의 일꾼이 되는 것이었습니다. 그는 예루살렘으로부터 일루리곤까지 그리스도의 복음을 편만하게 전했으며, 남의 터 위에 건축하지 않기 위해 그리스도의 이름을 부르지 않는 곳에서 복음을 전하기를 힘썼습니다. 이는 "주의 소식을 받지 못한 자들이 볼 것이요 듣지 못한 자들이 깨달으리라"(롬 15:21)는 이사야의 예언을 성취하는 것이었습니다.\n\n이제 바울은 새로운 계획을 품고 있습니다. 동방 지역에서의 사역을 마무리하고 서바나(스페인)로 가려는 것입니다. 그 여정 중에 로마를 방문하여 성도들과 교제하기를 간절히 원합니다. 그러나 먼저 예루살렘으로 가야 할 일이 있습니다. 마게도냐와 아가야의 이방인 교회들이 예루살렘의 가난한 성도들을 위해 모금한 연보를 전달해야 하는 것입니다. 바울은 이를 단순한 구제가 아닌 영적인 빚을 갚는 행위로 이해합니다. 이방인들이 유대인들로부터 영적인 것을 받았으니, 육적인 것으로 섬기는 것이 마땅하다는 것입니다.\n\n바울은 로마 교인들에게 간절한 기도를 부탁합니다. 예루살렘에는 여전히 그를 적대시하는 유대인들이 있었고, 생명의 위협까지 느끼고 있었기 때문입니다. 그는 무사히 예루살렘 사역을 마치고 기쁨으로 로마에 도착하여 그들과 함께 쉼을 얻기를 소망합니다.', E'오늘의 핵심\n바울은 그리스도를 본받아 약한 자를 돌보는 공동체의 모습을 제시하며, 복음이 전해지지 않은 땅 끝까지 나아가려는 선교적 비전을 품고 있습니다.\n\n묵상 질문\n1. 내가 속한 공동체에서 믿음이 약한 이들을 어떻게 품고 섬기고 있나요?\n2. 하나님께서 내게 주신 특별한 은혜와 사명은 무엇인가요?\n3. 영적인 것을 받은 자로서 물질적인 나눔을 실천하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-15', E'땅 끝 비전과 받음직한 섬김 (로마서 16장)', E'로마서 16장', E'로마서의 마지막 장은 바울의 따뜻한 인간관계와 초대교회의 아름다운 공동체성을 보여줍니다. 바울은 26명이나 되는 동역자들의 이름을 하나하나 부르며 문안합니다. 그저 형식적인 인사가 아니라, 각 사람의 특별한 헌신과 수고를 기억하며 감사를 표현합니다.\n\n먼저 바울은 겐그레아 교회의 일꾼 뵈뵈를 추천합니다. 그녀는 로마서를 전달하는 중요한 임무를 맡았으며, 바울은 그녀를 "여러 사람과 나의 보호자"라고 부릅니다. 이어서 브리스가와 아굴라 부부를 언급하는데, 그들은 바울의 목숨을 위해 자기들의 목까지도 내놓은 헌신적인 동역자들이었습니다. 이들의 집은 교회 모임 장소로 사용되었고, 이방인의 모든 교회가 그들에게 감사하고 있었습니다.\n\n특별히 주목할 점은 바울이 언급하는 사람들의 다양성입니다. 유대인과 이방인, 남자와 여자, 주인과 종, 부유한 자와 가난한 자가 그리스도 안에서 하나가 되어 있습니다. "그리스도 안에서 택하심을 입은 루포와 그의 어머니"를 언급하며, 루포의 어머니를 "곧 내 어머니"라고 부르는 바울의 표현에서 초대교회 성도들 간의 깊은 영적 가족애를 볼 수 있습니다.\n\n바울은 문안을 마치며 경고의 말씀도 잊지 않습니다. 교회 안에 분쟁을 일으키고 거치게 하는 자들을 경계하라고 권면합니다. 이들은 그리스도를 섬기지 않고 자기들의 배만 섬기며, 교활한 말로 순진한 자들을 미혹한다고 지적합니다. 그러나 바울은 두려움이 아닌 소망으로 편지를 마무리합니다. "평강의 하나님께서 속히 사탄을 너희 발 아래에서 상하게 하시리라"는 확신과 함께, 영세 전부터 감추어졌다가 이제 나타난 복음의 신비를 찬양합니다.', E'오늘의 핵심\n바울의 세심한 문안 인사는 초대교회가 다양한 배경의 사람들이 그리스도 안에서 하나 된 사랑의 공동체였음을 보여주며, 복음 사역은 혼자가 아닌 함께 이루어가는 것임을 가르쳐줍니다.\n\n묵상 질문\n1. 나는 신앙 공동체 안에서 누군가의 이름을 기억하며 그의 수고에 감사하고 있나요?\n2. 그리스도 안에서 다양한 배경의 사람들과 진정한 형제자매가 되는 것을 경험하고 있나요?\n3. 교회를 분열시키는 교활한 말과 아첨에 미혹되지 않으려면 어떤 분별력이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-17', E'마지막 예루살렘 방문 (사도행전 20장)', E'사도행전 20장', E'바울이 3차 선교여행을 마무리하며 예루살렘으로 향하는 여정은 결코 순탄하지 않았습니다. 유대인들의 해하려는 공모로 계획된 항로를 바꿔야 했고, 성령께서는 각 성에서 결박과 환난이 기다린다고 증언하셨습니다. 그럼에도 바울의 발걸음은 멈추지 않았습니다. 오히려 "내가 달려갈 길과 주 예수께 받은 사명 곧 하나님의 은혜의 복음을 증언하는 일을 마치려 함에는 나의 생명조차 조금도 귀한 것으로 여기지 아니하노라"(행 20:24)고 고백합니다.\n\n밀레도에서 에베소 교회 장로들을 불러 전한 바울의 고별 설교는 한 사역자의 삶 전체가 담긴 유언과 같았습니다. 그는 모든 겸손과 눈물로 주를 섬겼고, 유익한 것은 무엇이든지 거리낌 없이 전했으며, 하나님의 뜻을 다 전하는 일에 꺼리지 않았다고 증언합니다. 특별히 바울은 자신의 손으로 일하며 약한 사람들을 도왔고, "주는 것이 받는 것보다 복이 있다"는 주님의 말씀을 몸소 실천했습니다.\n\n이 고별의 순간에서 가장 인상적인 것은 바울과 장로들 사이의 깊은 사랑입니다. 3년 동안 밤낮 쉬지 않고 눈물로 각 사람을 훈계했던 바울의 헌신은 장로들의 마음을 움직였고, 그들은 크게 울며 바울의 목을 안고 입을 맞췄습니다. 이는 단순한 목회자와 교인의 관계를 넘어선, 복음 안에서 맺어진 깊은 영적 가족의 모습을 보여줍니다.\n\n드로아에서 밤새 말씀을 전하다가 유두고가 창에서 떨어져 죽은 사건은 또 다른 교훈을 줍니다. 바울은 당황하지 않고 청년을 안으며 생명이 있다고 선언했고, 실제로 그는 살아났습니다. 이 놀라운 기적 후에도 바울은 날이 새도록 계속해서 말씀을 전했습니다. 복음 전파에 대한 그의 열정은 어떤 상황에서도 식지 않았습니다.\n\n오늘 우리도 각자의 자리에서 달려갈 길이 있습니다. 때로는 유대인들의 공모처럼 예상치 못한 방해가 있을 수 있고, 앞날에 대한 불확실함이 우리를 주저하게 만들 수도 있습니다. 그러나 바울이 보여준 것처럼, 주님께 받은 사명이 분명하다면 우리는 담대히 나아갈 수 있습니다. 하나님의 은혜의 말씀이 우리를 능히 든든히 세우실 것입니다.', E'오늘의 핵심\n바울은 앞에 놓인 결박과 환난을 알면서도 하나님의 은혜의 복음을 증언하는 사명을 완수하기 위해 생명조차 아끼지 않고 예루살렘으로 향했습니다.\n\n묵상 질문\n1. 바울이 위험을 알면서도 예루살렘으로 향한 이유는 무엇이며, 나에게도 그런 사명이 있을까요?\n2. 바울처럼 눈물로 섬기며 복음을 전하는 삶을 살기 위해 내가 내려놓아야 할 것은 무엇일까요?\n3. "주는 것이 받는 것보다 복이 있다"는 말씀을 오늘 내 삶에서 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-18', E'마지막 예루살렘 방문 (사도행전 21장)', E'사도행전 21장', E'바울의 예루살렘 행은 성령의 경고와 동역자들의 만류 속에서도 계속됩니다. 두로에서 제자들은 성령의 감동으로 바울에게 예루살렘에 들어가지 말라고 권면했고, 가이사랴에서는 아가보 선지자가 바울의 띠로 자기 손발을 묶으며 체포를 예언했습니다. 그러나 바울의 대답은 단호했습니다. "나는 주 예수의 이름을 위하여 결박 당할 뿐 아니라 예루살렘에서 죽을 것도 각오하였노라"(행 21:13). 이는 맹목적인 고집이 아니라 부르신 이를 향한 깊은 신뢰에서 나온 결단이었습니다.\n\n예루살렘에 도착한 바울은 야고보와 장로들을 만나 이방인 선교의 열매들을 나누었습니다. 하지만 유대인 신자들 사이에서는 바울이 모세를 배반하고 할례와 관습을 버리라고 가르친다는 오해가 퍼져 있었습니다. 바울은 화평을 위해 결례를 행하며 율법도 존중함을 보여주려 했습니다. 그러나 아시아에서 온 유대인들이 바울을 보자 성전을 더럽혔다는 거짓 고발로 군중을 선동했고, 온 예루살렘이 소동에 휩싸입니다.\n\n바울이 군중에게 죽을 위기에 처했을 때, 하나님의 섭리는 로마 천부장의 개입으로 나타납니다. 소동의 소식을 들은 천부장이 군인들을 이끌고 달려와 바울을 체포함으로써 오히려 그의 생명을 구했습니다. 바울은 자신이 길리기아 다소의 시민임을 밝히고 백성들에게 변호할 기회를 얻습니다. 이 모든 과정은 복음이 예루살렘에서 로마까지 전파되도록 인도하시는 하나님의 더 큰 계획 안에 있었습니다.\n\n우리도 때로는 하나님의 뜻을 따르는 길에서 반대와 오해에 직면합니다. 주변의 만류가 사랑에서 나온 것일지라도, 하나님께서 주신 확실한 부르심이 있다면 믿음으로 나아가야 할 때가 있습니다. 바울이 보여준 것처럼, 그것은 무모함이 아니라 하나님의 주권을 신뢰하는 믿음의 행동입니다.', E'오늘의 핵심\n바울은 성령의 경고와 동역자들의 눈물 어린 만류에도 불구하고, 주 예수의 이름을 위해 죽을 것까지 각오하며 예루살렘으로 향합니다.\n\n묵상 질문\n1. 사랑하는 사람들의 만류와 하나님의 부르심 사이에서 갈등할 때, 무엇을 기준으로 결정해야 할까요?\n2. 오해와 거짓 고발 속에서도 하나님은 어떻게 바울을 보호하시고 그분의 계획을 이루어 가셨나요?\n3. 내가 주님의 이름을 위해 감당해야 할 희생이나 고난은 무엇인지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-19', E'마지막 예루살렘 방문 (사도행전 22장)', E'사도행전 22장', E'예루살렘 성전 뜰에서 체포된 바울이 로마 군대의 영문 계단에 서서 군중을 향해 자신의 이야기를 풀어놓습니다. 히브리어로 말을 시작하자 소란하던 군중이 조용해집니다. 바울은 자신이 철저한 유대인이었음을 먼저 밝힙니다. 다소에서 태어났지만 예루살렘에서 자랐고, 당대 최고의 율법학자 가말리엘 문하에서 수학했으며, 그들과 같은 열심으로 하나님을 섬겼다고 말합니다. 그 열심이 얼마나 컸던지 그리스도인들을 박해하여 죽이기까지 했고, 남녀를 가리지 않고 결박하여 옥에 넘겼습니다.\n\n그러나 다메섹으로 가는 길에서 모든 것이 바뀌었습니다. 정오의 태양보다 밝은 빛이 그를 둘러 비추었고, "사울아 사울아 네가 왜 나를 박해하느냐"는 음성이 들렸습니다. 그 음성의 주인은 바로 그가 박해하던 나사렛 예수였습니다. 이 만남은 바울의 삶을 완전히 뒤집어 놓았습니다. 박해자에서 증인으로, 율법의 수호자에서 복음의 전파자로 변화된 것입니다.\n\n바울의 변화는 단순한 종교적 전향이 아니었습니다. 하나님께서는 아나니아를 통해 바울에게 분명한 사명을 주셨습니다. "네가 그를 위하여 모든 사람 앞에서 네가 보고 들은 것에 증인이 되리라"(행 22:15). 더 나아가 예루살렘 성전에서 기도하던 중 환상을 통해 이방인의 사도로 부르심을 받았습니다. 바울이 과거 자신의 잘못을 고백하며 주저할 때, 주님은 단호하게 "떠나가라 내가 너를 멀리 이방인에게로 보내리라"고 명하셨습니다.\n\n이방인 선교라는 말이 나오자 군중은 다시 격분합니다. 그들에게 이방인과 유대인이 하나님 앞에 동등하다는 것은 받아들일 수 없는 신성모독이었습니다. 소동이 커지자 천부장은 바울을 영내로 끌고 가 채찍질하며 심문하려 했습니다. 그러나 바울이 로마 시민임을 밝히자 상황은 급변합니다. 로마법은 시민권자를 재판 없이 형벌에 처하는 것을 엄격히 금했기 때문입니다.\n\n바울의 증언은 복음이 민족과 신분의 장벽을 넘어선다는 것을 보여줍니다. 철저한 유대주의자였던 그가 이방인의 사도가 되었고, 로마 시민권이라는 세상의 특권도 복음 전파를 위한 도구로 사용되었습니다. 하나님의 구원 계획은 인간의 편견과 제도를 뛰어넘어 모든 민족에게 열려 있음을 바울의 삶이 증거하고 있습니다.', E'오늘의 핵심\n바울은 자신의 극적인 회심 경험을 통해 복음이 유대인과 이방인 모두를 위한 것임을 증거하며, 하나님께서는 바울의 로마 시민권까지도 복음 전파의 도구로 사용하십니다.\n\n묵상 질문\n1. 바울처럼 과거의 열심이 잘못된 방향이었음을 깨달은 경험이 있나요? 하나님은 그것을 어떻게 바로잡아 주셨나요?\n2. 내가 가진 신분이나 배경, 특권을 하나님 나라를 위해 어떻게 사용할 수 있을까요?\n3. 복음을 전할 때 상대방의 언어와 문화를 이해하려는 노력을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-20', E'마지막 예루살렘 방문 (사도행전 23장)', E'사도행전 23장', E'공회 앞에 선 바울의 모습은 예상치 못한 전개로 이어집니다. "범사에 양심을 따라 하나님을 섬겼노라"는 그의 고백에 대제사장 아나니아는 바울의 입을 치라고 명령합니다. 이에 바울은 "회칠한 담이여 하나님이 너를 치시리로다"라고 맞섭니다. 대제사장을 욕했다는 지적에 바울은 즉시 사과하며 성경 말씀을 인용합니다. 이 장면은 바울이 얼마나 철저하게 말씀에 순종하려 했는지를 보여줍니다.\n\n그러나 바울의 지혜는 여기서 더욱 빛을 발합니다. 공회가 사두개인과 바리새인으로 나뉘어 있음을 간파한 바울은 "죽은 자의 소망 곧 부활로 말미암아 내가 심문을 받노라"고 외칩니다. 이 한마디로 공회는 둘로 갈라졌고, 바리새인들 중 일부는 오히려 바울을 옹호하기 시작합니다. 신학적 진리를 활용한 바울의 지혜로운 대처는 위기의 순간을 모면하는 계기가 되었습니다.\n\n큰 분쟁으로 바울이 찢겨질 위기에 처하자 로마 천부장이 그를 구출해 영내로 데려갑니다. 그날 밤, 주님께서 바울 곁에 서서 말씀하십니다. "담대하라 네가 예루살렘에서 나의 일을 증언한 것 같이 로마에서도 증언하여야 하리라"(행 23:11). 사람들의 계략과 위협 속에서도 하나님의 계획은 흔들림이 없었습니다.\n\n다음 날 사십여 명의 유대인들이 바울을 죽이기 전에는 먹지도 마시지도 않겠다며 맹세합니다. 그러나 하나님은 바울의 생질을 통해 이 음모를 드러내시고, 로마 천부장은 즉시 대응합니다. 이백 명의 보병과 칠십 명의 기병, 그리고 이백 명의 창병이 바울 한 사람을 호송하게 됩니다. 로마 시민권자를 보호하는 로마법의 위력이었지만, 그 배후에는 로마에서도 복음을 증언해야 할 바울을 지키시는 하나님의 섭리가 있었습니다.\n\n천부장 글라우디오 루시아가 총독 벨릭스에게 보낸 편지는 바울에게 죽이거나 결박할 만한 죄가 없다고 명시합니다. 종교적 논쟁으로 시작된 고발이 정치적 사건이 되었고, 이제 바울은 더 높은 권력 앞에서 복음을 증언할 기회를 얻게 됩니다. 가이사랴로 향하는 바울의 여정은 결국 로마로 가는 길의 시작이었습니다. 하나님은 인간의 악한 계략조차도 당신의 선한 목적을 이루는 도구로 사용하십니다.', E'오늘의 핵심\n극심한 위협 속에서도 하나님은 바울 곁에 서서 위로하시며, 로마에서의 증언이라는 더 큰 사명을 확증해 주셨습니다.\n\n묵상 질문\n1. 위기의 순간에 지혜롭게 대처한 바울처럼, 나는 어떻게 믿음과 지혜를 균형 있게 사용할 수 있을까요?\n2. 사십 명의 맹세도 막지 못한 하나님의 계획을 보며, 내 삶을 향한 하나님의 주권을 어떻게 신뢰할 수 있을까요?\n3. "담대하라"는 주님의 음성이 오늘 내게 필요한 상황은 무엇이며, 어떻게 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-21', E'가이사라에서의 2년 (사도행전 24장)', E'사도행전 24장', E'가이사라로 호송된 바울에게 새로운 시련이 시작됩니다. 대제사장 아나니아는 단 닷새 만에 장로들과 변호사 더둘로를 대동하고 바울을 고소하기 위해 가이사라까지 찾아옵니다. 유대 종교 지도자들의 집요한 추격은 예수님을 십자가에 못 박았던 그 증오가 이제 예수님의 증인들을 향해 그대로 이어지고 있음을 보여줍니다.\n\n벨릭스 총독 앞에서 펼쳐진 재판은 진실과 거짓의 대결이었습니다. 더둘로는 바울을 "전염병 같은 자"요 "나사렛 이단의 우두머리"라고 비난하며 성전을 더럽히려 했다고 거짓 증언합니다. 그러나 바울은 담대하게 자신의 신앙을 변호합니다. 그는 자신이 믿는 것이 "그들이 이단이라 하는 도"이지만 사실은 율법과 선지자들의 글에 기록된 것을 그대로 믿는 것이며, 의인과 악인의 부활에 대한 소망을 품고 있다고 선포합니다.\n\n벨릭스 총독은 이미 기독교에 대해 어느 정도 알고 있었기에 판결을 연기합니다. 그는 바울에게 어느 정도 자유를 주며 친구들의 방문도 허락합니다. 더 놀라운 것은 벨릭스가 아내 드루실라와 함께 바울을 불러 복음을 듣는 장면입니다. 바울이 "의와 절제와 장차 오는 심판"을 강론하자 벨릭스는 두려워하며 "지금은 가라"고 말합니다. 그의 양심이 찔렸지만 회개에까지는 이르지 못한 것입니다.\n\n2년이라는 긴 시간이 흐릅니다. 벨릭스는 바울에게서 뇌물을 기대하며 자주 불러 대화를 나누지만, 끝내 바울을 석방하지 않습니다. 오히려 후임자 베스도에게 총독직을 넘기면서 유대인들의 환심을 사기 위해 바울을 그대로 구금해 둡니다. 하지만 이 모든 과정은 하나님께서 바울을 로마로 인도하시는 섭리의 한 부분이었습니다. 감옥이라는 제한된 공간에서도 복음은 총독과 그의 아내에게까지 전해졌고, 바울은 하나님의 때를 기다리며 충성된 증인의 삶을 살아갑니다.', E'오늘의 핵심\n가이사라 감옥에서 2년을 보낸 바울은 유대인들의 거짓 고소와 총독의 부패 속에서도 담대히 복음을 증거하며 하나님의 섭리를 신뢰합니다.\n\n묵상 질문\n1. 억울한 상황에서도 바울처럼 담대하게 진리를 증거할 수 있는 힘은 어디서 올까요?\n2. 벨릭스처럼 복음을 듣고도 "지금은 가라"고 미루고 있는 결단이 있나요?\n3. 지금의 답답한 상황도 하나님의 더 큰 계획의 일부일 수 있음을 믿고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-22', E'가이사라에서의 2년 (사도행전 25장)', E'사도행전 25장', E'벨릭스의 후임으로 베스도가 유대 총독으로 부임합니다. 새 총독이 부임하자마자 대제사장들과 유대인 지도자들이 찾아와 바울을 예루살렘으로 이송해 달라고 청원합니다. 2년이라는 시간이 흘렀음에도 바울을 향한 그들의 증오는 식지 않았고, 오히려 길에 매복하여 그를 죽이려는 음모까지 꾸미고 있었습니다. 베스도는 로마법에 따라 정식 재판을 진행하지만, 유대인들은 여전히 구체적인 증거 없이 바울을 고발할 뿐이었습니다.\n\n베스도는 전임자 벨릭스처럼 유대인들의 환심을 사려 했습니다. 그는 바울에게 예루살렘에서 재판받을 것을 제안하는데, 이는 사실상 바울을 유대인들에게 넘겨주려는 의도였습니다. 이 순간 바울은 로마 시민으로서 가진 최후의 권리를 행사합니다. "내가 가이사께 상소하노라"(행 25:11). 이 한마디로 바울의 운명은 완전히 달라집니다. 죄수의 신분이지만 로마로 가는 길이 열린 것입니다.\n\n며칠 후 아그립바 왕이 베스도를 방문했을 때, 베스도는 바울의 사건을 설명하며 흥미로운 고백을 합니다. 유대인들이 바울을 고발하는 내용이 그가 예상했던 악행이 아니라 "자기들의 종교와 또는 예수라 하는 이가 죽은 것을 살아 있다고 바울이 주장하는 그 일"에 관한 것뿐이었다는 것입니다. 로마 총독의 눈에는 이것이 종교적 논쟁일 뿐, 법적으로 죽을 죄가 아니었습니다.\n\n하나님께서는 바울이 로마로 가는 길을 놀라운 방법으로 열어 주셨습니다. 유대인들의 집요한 음모와 로마 총독의 정치적 계산, 그리고 바울의 지혜로운 결단이 맞물려 결국 하나님의 뜻이 이루어진 것입니다. 감옥에 갇혀 있던 2년의 시간도, 끊임없는 위협과 모함도 하나님의 계획을 막을 수 없었습니다. 오히려 이 모든 과정이 복음이 로마 제국의 중심부로 전해지는 통로가 되었습니다.', E'오늘의 핵심\n바울은 베스도의 정치적 타협을 거부하고 가이사에게 상소함으로써, 비록 죄수의 몸이지만 로마로 가는 하나님의 뜻을 이루어갑니다.\n\n묵상 질문\n1. 위기의 순간에 믿음의 결단을 내리기 위해 평소에 어떤 준비가 필요할까요?\n2. 하나님의 뜻이 인간의 계획과 상황을 통해 이루어지는 것을 경험한 적이 있나요?\n3. 현재 나의 어려운 상황이 오히려 하나님의 더 큰 계획을 위한 통로가 될 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-24', E'가이사라에서의 2년 (사도행전 26장)', E'사도행전 26장', E'가이사라에서 2년을 보낸 바울에게 새로운 기회가 찾아옵니다. 베스도 총독의 초청으로 방문한 아그립바 왕 앞에서 변론할 수 있게 된 것입니다. 아그립바는 헤롯 대왕의 증손자로서 유대인의 관습과 율법에 정통한 인물이었습니다. 바울은 이러한 아그립바 앞에서 자신의 신앙 여정을 담담히 풀어놓습니다.\n\n바울의 변론은 자신이 철저한 바리새인으로 살았던 과거로부터 시작됩니다. 그는 한때 예수의 이름을 대적하여 성도들을 박해하는 일에 앞장섰던 자신의 모습을 숨김없이 고백합니다. 그러나 다메섹으로 가는 길에서 부활하신 예수님을 만난 이후, 그의 삶은 완전히 뒤바뀌었습니다. "사울아 사울아 네가 어찌하여 나를 박해하느냐"(행 26:14)라는 주님의 음성은 그를 박해자에서 증인으로 변화시켰습니다.\n\n바울이 받은 소명은 분명했습니다. 이스라엘과 이방인들의 눈을 열어 어둠에서 빛으로, 사탄의 권세에서 하나님께로 돌아오게 하는 것이었습니다. 이는 단순한 종교 개종이 아니라 근본적인 삶의 전환을 의미했습니다. 바울은 이 하늘의 소명을 거스르지 않고 순종하여 다메섹과 예루살렘, 유대 온 땅과 이방인에게까지 회개의 복음을 전했습니다.\n\n바울의 열정적인 변론을 듣던 베스도는 그가 미쳤다고 소리쳤지만, 바울은 담대하게 참되고 온전한 말을 하고 있다고 답합니다. 그리고 아그립바 왕에게 직접적으로 도전합니다. 선지자들의 예언을 믿는다면 그리스도가 고난받고 부활하여 만민에게 빛이 되신다는 진리를 받아들일 수 있지 않겠느냐는 것입니다.\n\n아그립바는 바울의 설득에 동요했지만 결국 신앙 고백까지는 나아가지 못합니다. 그러나 바울의 무죄를 인정하며, 가이사에게 상소하지 않았다면 석방될 수 있었을 것이라고 말합니다. 이렇게 바울은 죄수의 신분으로도 왕과 총독 앞에서 복음을 증거하는 기회를 놓치지 않았습니다. 그의 삶 자체가 하나님의 은혜와 능력을 보여주는 살아있는 증거였습니다.', E'오늘의 핵심\n바울은 아그립바 왕 앞에서 자신의 회심 경험과 복음의 핵심을 담대히 증거하며, 어떤 상황에서도 그리스도의 증인으로서의 사명을 다합니다.\n\n묵상 질문\n1. 바울처럼 나의 신앙 여정을 다른 사람에게 분명하게 전할 수 있나요?\n2. 어려운 상황 속에서도 복음 전파의 기회를 찾고 활용하고 있나요?\n3. 내가 받은 하늘의 소명에 어떻게 순종하며 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-25', E'복음과 함께 고난 받으라 (디모데후서 1장)', E'디모데후서 1장', E'로마의 감옥에서 바울이 사랑하는 영적 아들 디모데에게 마지막 편지를 쓰고 있습니다. 네로 황제의 기독교 박해가 본격화되면서 바울은 자신의 순교가 임박했음을 알고 있었습니다. 이런 절박한 상황에서도 바울은 디모데를 향한 깊은 사랑과 복음에 대한 변함없는 열정을 담아 편지를 씁니다.\n\n바울은 디모데의 신앙의 뿌리를 상기시켜 줍니다. 외조모 로이스와 어머니 유니게로부터 이어진 거짓 없는 믿음이 디모데 안에도 있음을 확신한다고 말합니다. 이는 신앙이 단지 개인의 결단만이 아니라 가정과 공동체를 통해 전수되는 귀한 유산임을 보여줍니다. 바울은 안수를 통해 디모데에게 전달된 하나님의 은사를 다시 불일듯하게 하라고 권면합니다. \n\n특별히 주목할 것은 바울이 "하나님이 우리에게 주신 것은 두려워하는 마음이 아니요 오직 능력과 사랑과 절제하는 마음"(딤후 1:7)이라고 선언하는 부분입니다. 박해의 위협 앞에서 두려움에 사로잡힐 수 있는 디모데를 향해, 하나님께서 주신 것은 두려움이 아니라 담대함의 근원인 능력과 사랑, 그리고 절제임을 일깨워 줍니다.\n\n바울은 복음과 함께 고난을 받으라고 당부합니다. 이는 단순히 고난을 감내하라는 것이 아니라, 복음 증거자로서의 정체성을 분명히 하고 그에 따르는 대가를 기꺼이 치르라는 의미입니다. 바울 자신이 복음을 위해 갇힌 자가 되었지만 부끄러워하지 않는 이유는, 자신이 믿는 분이 누구인지 알고 그분이 맡긴 것을 끝까지 지키실 것을 확신하기 때문입니다.\n\n편지의 마지막 부분에서 바울은 많은 사람이 자신을 떠났지만 오네시보로처럼 끝까지 신실했던 이들을 언급합니다. 이는 박해의 시대에도 참된 믿음의 사람들이 있음을 보여주며, 디모데도 그러한 신실한 증인이 되기를 바라는 바울의 간절한 소망이 담겨 있습니다.', E'오늘의 핵심\n바울은 죽음을 앞둔 상황에서도 디모데에게 두려움이 아닌 하나님이 주신 능력과 사랑과 절제하는 마음으로 복음의 증인이 되라고 권면합니다.\n\n묵상 질문\n1. 내 신앙의 뿌리는 어디에 있으며, 누구를 통해 믿음의 유산을 물려받았는가?\n2. 복음 때문에 받을 수 있는 고난이나 불이익을 두려워하고 있지는 않은가?\n3. 하나님께서 내게 주신 은사를 다시 불일듯하게 하려면 무엇이 필요한가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-26', E'복음과 함께 고난 받으라 (디모데후서 2장)', E'디모데후서 2장', E'로마 감옥에서 최후를 준비하며 사랑하는 제자에게 편지를 쓰는 바울의 마음은 간절합니다. 디모데후서 2장은 바울이 디모데에게 전하는 영적 유산의 핵심을 담고 있습니다. 바울은 먼저 디모데에게 "그리스도 예수 안에 있는 은혜 가운데서 강하고"(딤후 2:1)라고 권면합니다. 이는 단순히 인간적인 의지나 노력이 아닌, 그리스도 안에서 주어지는 은혜로 강건해지라는 부탁입니다.\n\n바울은 복음 전수의 중요한 원리를 제시합니다. 디모데가 많은 증인 앞에서 들은 복음을 충성된 사람들에게 부탁하여, 그들이 또 다른 사람들을 가르칠 수 있도록 하라는 것입니다. 이는 복음이 한 세대에 머물지 않고 계속해서 전해져야 함을 보여줍니다. 바울은 이 사명을 감당하는 자의 자세를 세 가지 비유로 설명합니다. 병사처럼 자기 생활에 얽매이지 않고, 경기하는 자처럼 규칙을 따르며, 농부처럼 수고를 아끼지 않아야 한다는 것입니다.\n\n특별히 바울은 자신의 상황을 통해 복음의 능력을 증언합니다. 비록 자신은 죄인처럼 매여 있지만 "하나님의 말씀은 매이지 아니하니라"고 선포합니다. 이는 로마의 감옥이 복음의 전파를 막을 수 없음을 보여주는 놀라운 고백입니다. 바울은 택함 받은 자들을 위해 모든 것을 참는다고 말하며, 고난 중에도 소망을 잃지 않습니다.\n\n후반부에서 바울은 디모데에게 진리의 말씀을 옳게 분별하는 일꾼이 되라고 당부합니다. 당시 부활이 이미 지나갔다고 주장하며 성도들의 믿음을 흔드는 거짓 교사들이 있었습니다. 그러나 바울은 "하나님의 견고한 터는 섰으니"라고 확신합니다. 마지막으로 바울은 디모데에게 자신을 깨끗하게 하여 주인이 귀히 쓰는 그릇이 되라고 권면합니다. 청년의 정욕을 피하고, 깨끗한 마음으로 주를 부르는 자들과 함께 의와 믿음과 사랑과 화평을 추구하라는 것입니다. 이는 개인의 거룩함과 공동체적 신앙생활의 균형을 보여줍니다.', E'오늘의 핵심\n바울은 디모데에게 그리스도의 은혜 안에서 강건한 일꾼이 되어 복음을 신실하게 전수하고, 고난 중에도 진리의 말씀을 올바로 가르치는 귀한 그릇이 되라고 권면합니다.\n\n묵상 질문\n1. 복음을 다음 세대에 전수하기 위해 나는 어떤 ''충성된 사람''을 준비하고 있는가?\n2. 병사, 경기하는 자, 농부의 비유 중 지금 내게 가장 필요한 자세는 무엇인가?\n3. 하나님께 귀히 쓰임 받는 그릇이 되기 위해 내가 깨끗하게 해야 할 것은 무엇인가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-27', E'복음과 함께 고난 받으라 (디모데후서 3장)', E'디모데후서 3장', E'로마 감옥에서 최후의 시간을 보내고 있던 바울은 사랑하는 영적 아들 디모데에게 마지막 권면을 전합니다. 네로 황제의 기독교 박해가 극에 달하던 시기, 바울은 앞으로 교회가 직면하게 될 더 큰 영적 위기를 내다보며 디모데에게 경고의 메시지를 보냅니다. "말세에 고통하는 때가 이르러"라는 표현으로 시작되는 3장은 단순히 미래의 어느 시점을 가리키는 것이 아니라, 그리스도의 초림 이후 재림까지의 전 시대를 포괄하는 것입니다.\n\n바울이 제시하는 말세의 징조들은 놀랍도록 구체적입니다. 자기 사랑, 돈 사랑, 교만, 비방, 불효, 배은망덕 등 19가지 죄악의 목록은 타락한 인간 본성의 적나라한 모습을 보여줍니다. 특별히 "경건의 모양은 있으나 경건의 능력은 부인하는" 거짓 신앙의 모습은 오늘날 교회에도 깊이 경종을 울립니다. 겉으로는 신앙생활을 하는 것처럼 보이지만 실제로는 하나님의 능력을 체험하지 못하고 변화되지 않는 삶, 이것이야말로 가장 위험한 영적 상태입니다.\n\n이러한 거짓 교사들에 대한 경고와 함께, 바울은 디모데에게 자신의 삶을 본받으라고 권면합니다. 바울은 자신이 안디옥, 이고니온, 루스드라에서 당한 박해를 상기시키며, "무릇 그리스도 예수 안에서 경건하게 살고자 하는 자는 박해를 받으리라"(딤후 3:12)고 단언합니다. 이는 단순한 경고가 아니라 복음의 진리를 담대히 선포하는 자들이 필연적으로 겪게 될 고난에 대한 현실적 가르침입니다.\n\n그러나 바울의 메시지는 절망으로 끝나지 않습니다. 오히려 디모데에게 "배우고 확신한 일에 거하라"고 격려하며, 어려서부터 배운 성경의 가치를 상기시킵니다. 모든 성경이 하나님의 감동으로 된 것이며, 교훈과 책망과 바르게 함과 의로 교육하기에 유익하다는 이 선언은 성경의 권위와 충족성에 대한 가장 명확한 가르침입니다. 하나님의 말씀은 우리를 온전한 하나님의 사람으로 빚어가며, 모든 선한 일을 행할 능력을 갖추게 하는 은혜의 수단입니다.', E'오늘의 핵심\n말세의 어둠 속에서도 하나님의 말씀은 우리를 온전한 그리스도인으로 빚어가는 변함없는 진리이며, 경건한 삶은 필연적으로 고난을 동반하지만 주님께서 건져주십니다.\n\n묵상 질문\n1. 나는 경건의 모양만 있고 경건의 능력은 부인하는 형식적 신앙에 빠져 있지는 않은가?\n2. 복음을 위해 받는 고난을 두려워하기보다 오히려 영광으로 여기는 믿음이 있는가?\n3. 하나님의 말씀이 나를 온전케 하는 능력임을 날마다 경험하며 살고 있는가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-28', E'복음과 함께 고난 받으라 (디모데후서 4장)', E'디모데후서 4장', E'로마 감옥에서 죽음을 앞둔 바울이 사랑하는 제자 디모데에게 마지막 유언을 남기는 장면이 디모데후서 4장에 펼쳐집니다. 네로 황제의 극심한 박해로 인해 이제 곧 순교를 맞이하게 될 것을 직감한 사도는 하나님 앞과 그리스도 예수 앞에서 엄숙하게 명령합니다. "너는 말씀을 전파하라 때를 얻든지 못 얻든지 항상 힘쓰라"(딤후 4:2). 이것은 단순한 부탁이 아니라 심판주 되신 그리스도 앞에서 내리는 엄중한 명령이었습니다.\n\n바울은 자신의 죽음을 "전제와 같이 부어지는 것"으로 표현합니다. 구약의 제사에서 포도주를 제물 위에 부어 드리는 전제처럼, 자신의 생명을 하나님께 온전히 드리는 거룩한 제사로 여긴 것입니다. 그러면서도 그는 승리자의 확신에 차 있습니다. 선한 싸움을 싸우고, 달려갈 길을 마치고, 믿음을 지켰다는 고백은 복음 전도자로서의 사명을 충실히 감당한 자의 당당한 선언입니다.\n\n특별히 주목할 것은 바울이 홀로 남겨진 상황입니다. 데마는 세상을 사랑하여 그를 떠났고, 다른 동역자들도 각자의 사역지로 흩어졌습니다. 첫 번째 변론 때는 아무도 곁에 없었습니다. 그러나 바울은 원망하지 않습니다. 오히려 주께서 곁에 서서 힘을 주셨고, 복음이 온전히 전파되도록 하셨음을 감사합니다. 이것이 복음을 위해 생명을 바친 사도의 마지막 모습입니다.\n\n바울은 디모데에게 겨울 전에 속히 오라고 부탁하며, 겉옷과 책들을 가져오라고 당부합니다. 죽음을 앞둔 순간에도 말씀을 연구하고자 하는 그의 열정이 우리의 마음을 뜨겁게 합니다. 이제 의의 면류관이 예비되었다는 확신 속에서, 주의 나타나심을 사모하는 모든 자들에게도 동일한 상급이 있을 것이라는 소망을 전합니다.', E'오늘의 핵심\n죽음을 앞둔 바울은 디모데에게 때를 얻든지 못 얻든지 말씀을 전파하라고 명령하며, 자신은 선한 싸움을 마치고 의의 면류관을 기다린다는 승리의 확신을 고백합니다.\n\n묵상 질문\n1. 바울이 홀로 남겨진 상황에서도 주님이 함께하심을 고백할 수 있었던 믿음이 내게도 있습니까?\n2. 때를 얻든지 못 얻든지 복음을 전해야 하는 이유는 무엇이며, 나는 어떤 상황에서 복음 전파를 주저합니까?\n3. 인생의 마지막 순간에 "선한 싸움을 싸우고 믿음을 지켰다"고 고백할 수 있으려면 오늘 어떻게 살아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-29', E'오직 완전하신 예수 그리스도 (히브리서 1장)', E'히브리서 1장', E'옛 언약의 시대에 하나님께서는 여러 시대에 걸쳐 여러 선지자들을 통해 조상들에게 말씀하셨습니다. 그러나 이제 마지막 때에 이르러 하나님께서는 아들을 통해 우리에게 말씀하십니다. 히브리서는 이 놀라운 전환점을 선포하며 시작됩니다. 하나님의 최종적이고 완전한 계시가 바로 아들 예수 그리스도를 통해 주어졌다는 것입니다.\n\n히브리서 기자는 예수님의 탁월하심을 세 가지 차원에서 설명합니다. 첫째, 그분은 만유의 상속자이시며 만물을 창조하신 분입니다. 둘째, 그분은 하나님의 영광의 광채이시며 본체의 형상으로서 능력의 말씀으로 만물을 붙드시는 분입니다. 셋째, 죄를 정결하게 하는 구속 사역을 완성하시고 하나님 우편에 앉으신 분입니다. 이는 예수님께서 창조와 섭리와 구속의 전 영역에서 하나님의 아들로서 완전한 권세를 가지고 계심을 보여줍니다.\n\n특별히 1장은 예수님과 천사들을 비교하며 그분의 우월성을 강조합니다. 당시 유대인들에게 천사는 하나님의 말씀을 전달하는 중요한 존재였습니다. 그러나 히브리서는 구약성경을 인용하며 예수님께서 천사들과는 비교할 수 없을 만큼 탁월하신 분임을 증명합니다. "너는 내 아들이라"(시 2:7)는 선언은 천사 중 누구에게도 주어진 적이 없는 독특한 신분을 나타냅니다. 오히려 모든 천사들이 그분께 경배하도록 명령받았습니다.\n\n천사들은 "섬기는 영"으로서 구원받을 상속자들을 위해 보내심을 받은 존재들입니다. 반면 아들은 영원한 보좌를 가지시고 의와 공평으로 다스리시는 왕이십니다. 천사들은 피조물이지만 아들은 창조주이십니다. 만물은 변하고 낡아지지만 그분만은 영원히 동일하십니다. 이러한 대조를 통해 히브리서는 예수님을 통한 계시와 구원이 얼마나 확실하고 영광스러운 것인지를 우리에게 깨닫게 합니다.', E'오늘의 핵심\n하나님께서는 마지막 때에 아들 예수 그리스도를 통해 최종적이고 완전한 계시를 주셨으며, 그분은 모든 천사보다 탁월하신 창조주이시자 구속주이십니다.\n\n묵상 질문\n1. 예수님이 하나님의 최종 계시라는 사실이 내 신앙생활에 어떤 의미를 주나요?\n2. 천사보다 뛰어나신 예수님의 위엄을 묵상할 때 내 마음에 어떤 경배가 일어나나요?\n3. 영원히 변치 않으시는 주님을 의지하며 오늘 하루를 어떻게 살아가시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-07-31', E'오직 완전하신 예수 그리스도 (히브리서 2장)', E'히브리서 2장', E'히브리서 기자는 복음의 진리를 들은 신자들이 "흘러 떠내려가지 않도록" 주의하라고 권면합니다. 물이 흐르듯 신앙이 서서히 미끄러져 나가는 것을 경계하라는 말씀입니다. 천사들을 통해 전해진 구약의 율법도 범법자들에게 엄중한 심판을 가져왔는데, 하물며 하나님의 아들이 직접 선포하신 구원의 복음을 소홀히 여긴다면 그 결과가 얼마나 심각하겠습니까. \n\n본문은 예수님의 성육신이 지닌 놀라운 의미를 보여줍니다. 창조주께서 피조물인 천사보다 "잠시 동안 못하게" 되신 것은 인류를 구원하시기 위함이었습니다. 시편 8편을 인용하며 히브리서 기자는 하나님께서 인간에게 주신 원래의 영광스러운 지위를 상기시킵니다. 그러나 죄로 인해 그 지위를 잃어버린 인간을 회복시키기 위해 예수님께서 친히 인간이 되셨다는 것입니다.\n\n"자녀들은 혈과 육에 속하였으매 그도 또한 같은 모양으로 혈과 육을 함께 지니심은"(히 2:14) 예수님께서 우리와 동일한 인간 본성을 취하신 이유를 명확히 보여줍니다. 죽음의 권세를 깨뜨리고 죽음의 공포에 매여 있는 인류를 해방시키기 위해서는 그분 자신이 죽음을 경험하셔야 했습니다. 이것이 바로 성육신의 신비이자 구원의 핵심입니다.\n\n더 나아가 예수님은 단순히 인간이 되신 것이 아니라 우리의 "형제"가 되셨습니다. 거룩하게 하시는 분과 거룩하게 함을 받는 자들이 한 근원에서 났기에, 예수님은 우리를 형제라 부르시기를 부끄러워하지 않으십니다. 이는 단순한 동정이 아닌, 완전한 연대와 일체감을 의미합니다. \n\n이렇게 인간의 연약함을 친히 경험하신 예수님은 "자비하고 신실한 대제사장"이 되셨습니다. 시험과 고난을 당하신 경험이 있기에 시험받는 자들을 능히 도우실 수 있습니다. 이것이 바로 히브리서가 전하는 위로와 소망의 메시지입니다. 우리의 대제사장은 하늘 높은 곳에서 우리를 내려다보시는 분이 아니라, 우리와 같은 시험을 받으시고 우리의 연약함을 체휼하신 분이십니다.', E'오늘의 핵심\n예수님께서는 인간의 혈과 육을 입으시고 죽음을 경험하심으로써 죽음의 권세를 깨뜨리셨으며, 시험받는 우리를 능히 도우실 수 있는 자비롭고 신실한 대제사장이 되셨습니다.\n\n묵상 질문\n1. 내 신앙이 "흘러 떠내려가고" 있지는 않은지 점검해 보셨나요?\n2. 예수님이 나의 형제가 되어주셨다는 사실이 오늘 나에게 어떤 위로가 됩니까?\n3. 지금 겪고 있는 시험과 고난 속에서 예수님의 도우심을 어떻게 경험할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-01', E'오직 완전하신 예수 그리스도 (히브리서 3장)', E'히브리서 3장', E'히브리서 기자는 믿음의 여정에서 흔들리는 성도들에게 예수님과 모세를 비교하며 더 큰 확신을 심어줍니다. 모세는 이스라엘 역사상 가장 위대한 지도자였고, 하나님과 대면하여 말씀을 받은 선지자였습니다. 유대인들에게 모세는 율법을 전해준 특별한 존재였기에, 그들이 다시 유대교로 돌아가려는 마음을 품는 것도 이해할 만했습니다.\n\n그러나 히브리서는 분명한 구별을 제시합니다. 모세는 하나님의 집에서 종으로서 충성했지만, 예수님은 그 집을 지으신 아들이라는 것입니다. 종과 아들의 차이는 하늘과 땅만큼 큽니다. 모세는 장차 오실 메시아를 증언하는 역할을 했지만, 예수님은 바로 그 약속의 성취자이십니다. 건축자가 건물보다 존귀하듯이, 하나님의 집을 세우신 그리스도는 그 집에서 섬긴 모세보다 더욱 영광을 받으실 분입니다.\n\n이어서 히브리서는 광야에서의 이스라엘 백성의 실패를 상기시킵니다. 그들은 하나님의 놀라운 기적들을 목격하고도 불신앙으로 인해 약속의 땅에 들어가지 못했습니다. "그들이 항상 마음이 미혹되어 내 길을 알지 못하는도다"(히 3:10)라는 하나님의 탄식은 오늘날 우리에게도 경고가 됩니다. 40년 동안 하나님의 행사를 보고도 마음이 완고해진 그들처럼, 우리도 은혜 가운데서 무감각해질 수 있기 때문입니다.\n\n그래서 히브리서는 "오늘"이라는 단어를 반복하며 긴급함을 전합니다. 믿음은 과거의 경험이나 미래의 계획이 아니라 오늘의 결단입니다. 서로 권면하며 믿음의 확신을 끝까지 견고히 붙잡는 것, 그것이 그리스도와 함께 참여한 자가 되는 길입니다. 외적인 핍박이나 내적인 의심이 찾아올 때, 우리는 더욱 예수님께 시선을 고정해야 합니다. 모세보다 뛰어나신 그분 안에서만 참된 안식을 누릴 수 있기 때문입니다.', E'오늘의 핵심\n예수님은 하나님의 집에서 종으로 충성한 모세와 달리 그 집의 주인이신 아들이시며, 우리는 오늘 믿음의 확신을 붙잡아 그분의 안식에 들어가야 합니다.\n\n묵상 질문\n1. 내가 의지하고 있는 것들과 비교할 때 예수님은 정말 가장 존귀한 분으로 여겨지고 있나요?\n2. 광야의 이스라엘처럼 은혜 가운데서도 마음이 완고해진 부분은 없는지 돌아볼까요?\n3. "오늘"이라는 긴급함으로 누군가를 권면하고 격려해야 할 사람은 누구인가요?');
